// NOTE: WAV mapping tables (sMmInstWavMap, sMmEffectWavMap, sMmDrumWavMap) were removed.
// All audio samples come from mm.o2r via ADPCM decoding — no filesystem WAV files needed.

// Form voice base addresses and transposes
#define MM_VOICE_FD_BASE 0x6800
#define MM_VOICE_HL_BASE 0x6820
#define MM_VOICE_DEKU_BASE 0x6880
#define MM_VOICE_ZORA_BASE 0x68A0
#define MM_VOICE_GORON_BASE 0x68C0

// Pitch factor for semitone transpose: 2^(semitones/12)
static f32 MmDirectAudio_TransposeFactor(s32 semitones) {
    // Fast lookup for common values
    if (semitones == 0)
        return 1.0f;
    if (semitones == 3)
        return 1.189207f; // 2^(3/12) - Deku/Zora voice pitch
    if (semitones == 4)
        return 1.259921f; // 2^(4/12) - Goron voice pitch
    if (semitones == 1)
        return 1.059463f; // 2^(1/12)
    // General case
    return powf(2.0f, (f32)semitones / 12.0f);
}

// Helper: check if a SoundFontSound has a valid sample loaded
static inline bool MmDirectAudio_SoundValid(SoundFontSound* s) {
    return s && s->sample && s->sample->sampleAddr;
}

// Get SoundFontSound from an instrument at a specific MIDI note.
// Many MM instruments only populate normalNotesSound, leaving low/high splits NULL.
// If the MIDI note selects a split with no sample, we fall back to any valid split.
static SoundFontSound* MmDirectAudio_GetInstrumentSound(SoundFont* font, u8 instrumentIdx, u8 midiNote) {
    if (!font || !font->instruments)
        return nullptr;
    if (instrumentIdx >= font->numInstruments)
        return nullptr;

    Instrument* inst = font->instruments[instrumentIdx];
    if (!inst || !inst->loaded)
        return nullptr;

    // Select the correct pitch split based on MIDI note
    SoundFontSound* sound;
    if (midiNote < inst->normalRangeLo) {
        sound = &inst->lowNotesSound;
    } else if (midiNote <= inst->normalRangeHi) {
        sound = &inst->normalNotesSound;
    } else {
        sound = &inst->highNotesSound;
    }

    // If the selected split has a valid sample, use it
    if (MmDirectAudio_SoundValid(sound))
        return sound;

    // Fallback: most instruments only populate normalNotesSound.
    // Try normalNotesSound first (most common), then low, then high.
    if (MmDirectAudio_SoundValid(&inst->normalNotesSound))
        return &inst->normalNotesSound;
    if (MmDirectAudio_SoundValid(&inst->lowNotesSound))
        return &inst->lowNotesSound;
    if (MmDirectAudio_SoundValid(&inst->highNotesSound))
        return &inst->highNotesSound;

    return nullptr;
}

// Same as GetInstrumentSound but skips the inst->loaded check.
// SoH's AudioSoundFontFactory always sets loaded=0 (managed by OOT's AudioLoad, not us).
// Only safe for dedicated instrument soundfonts loaded from mm.o2r (gakki: SF29/34/38).
static SoundFontSound* MmDirectAudio_GetInstrumentSoundDirect(SoundFont* font, u8 instrumentIdx, u8 midiNote) {
    if (!font || !font->instruments)
        return nullptr;
    if (instrumentIdx >= font->numInstruments)
        return nullptr;

    Instrument* inst = font->instruments[instrumentIdx];
    if (!inst)
        return nullptr;

    SoundFontSound* sound;
    if (midiNote < inst->normalRangeLo) {
        sound = &inst->lowNotesSound;
    } else if (midiNote <= inst->normalRangeHi) {
        sound = &inst->normalNotesSound;
    } else {
        sound = &inst->highNotesSound;
    }

    if (MmDirectAudio_SoundValid(sound))
        return sound;
    if (MmDirectAudio_SoundValid(&inst->normalNotesSound))
        return &inst->normalNotesSound;
    if (MmDirectAudio_SoundValid(&inst->lowNotesSound))
        return &inst->lowNotesSound;
    if (MmDirectAudio_SoundValid(&inst->highNotesSound))
        return &inst->highNotesSound;

    return nullptr;
}

// Stored pitch scale for the most recent GetSound call
static f32 sMmLastPitchScale = 1.0f;

// Get SoundFontSound for an MM SFX ID with correct instrument/effect mapping
static SoundFontSound* MmDirectAudio_GetSound(u16 mmSfxId) {
    s32 bank = MM_SFX_BANK_INDEX(mmSfxId);
    s32 sfxIndex = MM_SFX_SOUND_INDEX(mmSfxId);
    sMmLastPitchScale = 1.0f;

    SoundFont* font0 = MmSfx_LoadFont(0); // Soundfont_0 - main SFX font
    if (!font0) {
        MMSFX_LOG("[MmDirectAudio] Failed to load Soundfont_0");
        return nullptr;
    }

    // =========================================================================
    // Voice bank (6): Direct index into Soundfont_0.soundEffects[]
    //
    // MM's voice bank has 0x100 entries (0x6800-0x68FF). Each form has its own
    // 0x20-entry block with unique samples in soundEffects[]:
    //   Fierce Deity: 0x6800-0x681F → soundEffects[0-31]
    //   Human Link:   0x6820-0x683F → soundEffects[32-63]
    //   NPC voices:   0x6840-0x687F → soundEffects[64-127]
    //   Deku:         0x6880-0x689F → soundEffects[128-159]
    //   Zora:         0x68A0-0x68BF → soundEffects[160-191]
    //   Goron:        0x68C0-0x68DF → soundEffects[192-223]
    //   Mask Scents:  0x68E0-0x68FF → soundEffects[224-255]
    //
    // Each form has its OWN voice samples — Goron does NOT reuse Adult Link!
    // sfxIndex directly indexes into soundEffects[].
    // =========================================================================
    if (bank == 6) {
        // Voice bank mapping: sfxIndex → soundEffects[] index.
        // Formula: effectIdx = (transpose << 6) + effect_index_from_array.
        // The MM SF0 array is organized in 64-entry blocks per `transpose` value;
        // each form's samples live in their own block. Confirmed by POO_WAIT
        // (transpose=1, effect=35) playing correctly at index 99.
        //
        // Block layout (transpose: block start):
        //   FD:     CHAN_B87B  trans=0  → block 0   (effects  0-31)
        //   Human:  CHAN_B87B  trans=0  → block 0   (effects 32-63 ARRAY)
        //   NPC:    CHAN_*     trans=1  → block 1   (effects 64+)
        //   Deku:   CHAN_BC5E  trans=3  → block 3   (effects 192+)
        //   Zora:   CHAN_BCF3  trans=3  → block 3   (effects 192+, different range)
        //   Goron:  CHAN_BD84  trans=4  → block 4   (effects 256+)
        //   Scents: LAYER_BE06 trans=1  → block 1   (effects 64+)
        u16 effectIdx;
        if (sfxIndex < 0x20) {
            // Fierce Deity (0x00-0x1F): CHAN_B87B trans=0
            // Each action maps to a specific CHAN with its own effect array
            // From voicebank_table.h lines 3-34 + seq_0 channel handlers
            // Verified 1:1 against zeldaret/mm seq_0.prg.seq + voicebank_table.h
            static const u16 sFdActionToSfxId[] = {
                0,  // 0x6800 SWORD_N:    B690 ARRAY_B6A0={0,1,2,3}
                4,  // 0x6801 SWORD_L:    B6AB ARRAY_B6CD={4,5}
                0,  // 0x6802 LASH:       CHAN_VO_LI_LASH=cdelay1+end (SILENT)
                0,  // 0x6803 HANG:       CHAN_VO_LI_LASH (SILENT)
                0,  // 0x6804 CLIMB_END:  CHAN_VO_LI_LASH (SILENT)
                9,  // 0x6805 DAMAGE_S:   B72D ARRAY_B73E={9,10,11}
                12, // 0x6806 FREEZE:     B747 ARRAY_B758={12,13,14}
                0,  // 0x6807 FALL_S:     CHAN_VO_LI_LASH (SILENT)
                15, // 0x6808 FALL_L:     B779 ARRAY_B78A={15,16}
                19, // 0x6809 BREATH_REST:B791 ARRAY_B7A2={19,23}
                56, // 0x680A BREATH_DRK: ldlayer LAYER_B7AA SF0_EFFECT_56
                13, // 0x680B DOWN:       ldlayer LAYER_B7B2 t=1 {13,14,15}
                15, // 0x680C TAKEN:      B7C2 ARRAY_B7D3={15,16}
                9,  // 0x680D HELD:       →DAMAGE_S B72D {9,10,11}
                0,  // 0x680E SNEEZE:     CHAN_0048 (system, no voice effect)
                0,  // 0x680F SWEAT:      CHAN_0048 (system)
                0,  // 0x6810 DRINK:      CHAN_0048 (system)
                0,  // 0x6811 RELAX:      CHAN_0048 (system)
                0,  // 0x6812 PUTAWAY:    B66E ARRAY_B7FB={0}
                3,  // 0x6813 GROAN:      ldlayer LAYER_BA2F t=1 SF0_EFFECT_3
                27, // 0x6814 AUTO_JUMP:  B803 complex, primary eff=27
                5,  // 0x6815 MAGIC_NALE: B66E ARRAY_B82A={5}
                9,  // 0x6816 SURPRISE:   CHAN_0048 (system) — fallback to DAMAGE_S
                4,  // 0x6817 MAGIC_FROL: B66E ARRAY_B83B={4}
                6,  // 0x6818 PUSH:       CHAN_0048 (system) — fallback
                6,  // 0x6819 HOOKSHOT:   B66E ARRAY_B857={6}
                12, // 0x681A LAND_DMG:   B66E ARRAY_B862={12}
                0,  // 0x681B MAGIC_START:CHAN_0048 (system)
                0,  // 0x681C MAGIC_ATK:  CHAN_0048 (system)
                15, // 0x681D BL_DOWN:    B779 ARRAY_B78A={15,16}
                13, // 0x681E DEMO_DMG:   B66E ARRAY_B879={13}
                0,  // 0x681F LAST:       B690 ARRAY_B6A0={0,1,2,3}
            };
            u8 action = sfxIndex;
            effectIdx = (action < 32) ? sFdActionToSfxId[action] : 0;
        } else if (sfxIndex < 0x40) {
            // Human Link (0x20-0x3F): trans=0, shares handlers with Deku but trans=0
            // CHAN_B87B sets transposition=0. Human DUMMY_32+ channels use same
            // handlers as Deku DUMMY_128+ but with trans=0 instead of trans=3.
            // The effect indices are the SAME as Deku's sDekuActionToSfxId but
            // recomputed with trans=0: sfxId = (0<<6)+effect = effect directly.
            // Since we can't easily separate, use trans=0 versions of the Deku table.
            static const u16 sHumanActionToSfxId[] = {
                28, // 0x6820 SWORD_N:  eff=28
                32, // 0x6821 SWORD_L:  eff=32
                28, // 0x6822 LASH:     same as SWORD_N
                34, // 0x6823 HANG:     eff=34
                35, // 0x6824 CLIMB_END:eff=35
                37, // 0x6825 DAMAGE_S: eff=37
                40, // 0x6826 FREEZE:   eff=40
                45, // 0x6827 FALL_S:   eff=45
                43, // 0x6828 FALL_L:   eff=43
                47, // 0x6829 BREATH:   eff=47
                52, // 0x682A BREATH_D: eff=52
                64, // 0x682B DOWN:     trans=1,eff=0 → 64
                43, // 0x682C TAKEN:    eff=43
                20, // 0x682D HELD:     eff=20
                20, // 0x682E SNEEZE:   fallback
                20, // 0x682F SWEAT:    fallback
                51, // 0x6830 DRINK:    eff=51
                20, // 0x6831 RELAX:    fallback
                20, // 0x6832 PUTAWAY:  fallback
                20, // 0x6833 GROAN:    fallback
                53, // 0x6834 AUTO_JUMP:eff=53
                20, // 0x6835 MAGIC_N:  fallback
                37, // 0x6836 SURPRISE: eff=37 (reuse)
                20, // 0x6837 MAGIC_F:  fallback
                35, // 0x6838 PUSH:     eff=35
                20, // 0x6839 HOOKSHOT: fallback
                41, // 0x683A LAND_DMG: eff=41
                20, // 0x683B MAGIC_S:  fallback
                20, // 0x683C MAGIC_A:  fallback
                20, // 0x683D BL_DOWN:  fallback
                20, // 0x683E DEMO_DMG: fallback
                28, // 0x683F LAST:     fallback=SWORD_N
            };
            u8 action = sfxIndex - 0x20;
            effectIdx = (action < 32) ? sHumanActionToSfxId[action] : 28;
        } else if (sfxIndex < 0x80) {
            // NPC voices (0x40-0x7F)
            effectIdx = 64 + (sfxIndex - 0x40);
        } else if (sfxIndex < 0xA0) {
            // Deku (0x80-0x9F). Each Deku channel `call CHAN_BC5E (or BC64); jump CHAN_B***`.
            // CHAN_BC5E sets LAYER_B65B transpose=3. CHAN_BC64 sets vibrato 128/88.
            // SAMPLES are stored pre-transposed in mm.o2r's SF0 (verified empirically:
            // MS-of-Scents POO_WAIT at index (1<<6)+35=99 plays its correct sample, not
            // the raw 35 sample). So `effectIdx = (transpose<<6) + raw_effect` IS the
            // right sample-selection formula. The vibrato wiring below handles the
            // per-channel modulation that was missing.
            //
            // FALLBACK = 192 (Deku idle grunt, (3<<6)+0). NEVER use values outside the
            // Deku block 192-255 — earlier versions had several slots leaking into FD
            // (0..63), Human Link (64..127), or NPC (128..191) blocks, causing Deku
            // voices to play OTHER FORMS' samples. MM seq_0 maps most Deku DUMMY_*
            // slots to silent dummy channels, so falling back to the Deku base grunt
            // is the safe choice — never the WRONG form's voice.
            u8 action = sfxIndex - 0x80;
            static const u16 sDekuActionToSfxId[] = {
                // action  sfxId       CHAN→jump→arr           formula
                220, // 0x6880 DUMMY_128 BC5E→B885 [28..]  (3<<6)+28
                224, // 0x6881 DUMMY_129 BC5E→B8A1 [32,33] (3<<6)+32
                220, // 0x6882
                226, // 0x6883 DUMMY_131 BC64→B8E5 [34,50] (3<<6)+34  (vibrato)
                227, // 0x6884 DUMMY_132 BC5E→B912 [35,36] (3<<6)+35
                229, // 0x6885 DUMMY_133 BC5E→B92A [37..]  (3<<6)+37
                232, // 0x6886 DUMMY_134 BC5E→B944 [40..]  (3<<6)+40
                237, // 0x6887 DUMMY_135 BC5E→B95E [45,46] (3<<6)+45
                235, // 0x6888 DUMMY_136 BC5E→B976 [43,44] (3<<6)+43
                239, // 0x6889 DUMMY_137 BC5E→B98E [47,48] (3<<6)+47
                244, // 0x688A DUMMY_138 BC64→BCA8 [52]    (3<<6)+52  (vibrato)
                192, // 0x688B DOWN — was 64 (HUMAN LINK BLOCK leak); MM channel silent
                235, // 0x688C DUMMY_140 BC5E→B9BE [43,44] (3<<6)+43
                212, // 0x688D DUMMY_141 BC5E→B9D6 [20]    (3<<6)+20
                192, // 0x688E SNEEZE — was 20 (FD BLOCK leak); MM channel silent
                192, // 0x688F SWEAT — was 20 (FD BLOCK leak); MM channel silent
                243, // 0x6890 DUMMY_144 BC64→BCC7 [51]    (3<<6)+51  (vibrato)
                192, // 0x6891 RELAX — was 20 (FD BLOCK leak); MM channel silent
                192, // 0x6892 SWORD_PUTAWAY — was 20 (FD BLOCK leak); MM channel silent
                192, // 0x6893 GROAN — was 20 (FD BLOCK leak); MM channel silent
                245, // 0x6894 DUMMY_148 BC64→BA3B [53,54] (3<<6)+53  (vibrato)
                192, // 0x6895 MAGIC_NALE — was 20 (FD BLOCK leak); MM channel silent
                192, // 0x6896 SURPRISE — was 137 (NPC BLOCK leak); MM channel silent
                192, // 0x6897 MAGIC_FROL — was 20 (FD BLOCK leak); MM channel silent
                227, // 0x6898 DUMMY_152 BC5E→BA84 [35]    (3<<6)+35
                192, // 0x6899 HOOKSHOT_HANG — was 20 (FD BLOCK leak); MM channel silent
                241, // 0x689A DUMMY_154 BC5E→BA9A [49]    (3<<6)+49
                192, // 0x689B MAGIC_START — was 20 (FD BLOCK leak); MM channel silent
                192, // 0x689C MAGIC_ATTACK — was 20 (FD BLOCK leak); MM channel silent
                192, // 0x689D BL_DOWN — was 20 (FD BLOCK leak); MM channel silent
                192, // 0x689E DEMO_DAMAGE — was 20 (FD BLOCK leak); MM channel silent
                192, // 0x689F LAST — was 28 (FD BLOCK leak); base Deku grunt
            };
            effectIdx = (action < 32) ? sDekuActionToSfxId[action] : 192;
        } else if (sfxIndex < 0xC0) {
            // Zora (0xA0-0xBF) → CHAN_BCF3 trans=3 / CHAN_BCF9 vibrato 240/32.
            u8 action = sfxIndex - 0xA0;
            static const u16 sZoraActionToSfxId[] = {
                192, // 0x68A0 BCF3→B690 [0..]   (3<<6)+0
                196, // 0x68A1 BCF3→B6AB [4,5]   (3<<6)+4
                202, // 0x68A2 BCF3→B6D4 [10,11] (3<<6)+10
                198, // 0x68A3 BCF3→B6FD [6,25]  (3<<6)+6
                199, // 0x68A4 BCF3→B715 [7,8]   (3<<6)+7
                201, // 0x68A5 BCF3→B72D [9..]   (3<<6)+9
                204, // 0x68A6 BCF3→B747 [12..]  (3<<6)+12
                209, // 0x68A7 BCF3→B761 [17,18] (3<<6)+17
                207, // 0x68A8 BCF3→B779 [15,16] (3<<6)+15
                211, // 0x68A9 BCF3→B791 [19,23] (3<<6)+19
                192, // 0x68AA DUMMY_170 BCF9 (vibrato 240/32)
                192, // 0x68AB
                207, // 0x68AC BCF3→B7C2 [15,16] (3<<6)+15
                201, // 0x68AD BCF3→B72D
                192, 192, 192, 192, 192, 192,                    // 0x68AE..68B3
                192, 192, 192, 192,                              // 0x68B4..68B7 (DUMMY_180 BCF9 vibrato)
                199, // 0x68B8 BCF3→B846 [7] (3<<6)+7
                192,
                204, // 0x68BA BCF3→B85C [12] (3<<6)+12
                192, 192, 192, 192, 192,                         // 0x68BB..68BF
            };
            effectIdx = (action < 32) ? sZoraActionToSfxId[action] : 192;
        } else if (sfxIndex < 0xE0) {
            // Goron (0xC0-0xDF) → CHAN_BD84 sets transpose=4. Same handlers as FD.
            u8 action = sfxIndex - 0xC0;
            static const u16 sGoronActionToSfxId[] = {
                256, // 0x68C0 SWORD_N    B690 [0..]   (4<<6)+0
                260, // 0x68C1 SWORD_L    B6AB [4,5]   (4<<6)+4
                266, // 0x68C2 LASH       B6D4 [10,11] (4<<6)+10
                262, // 0x68C3 HANG       B6FD [6,25]  (4<<6)+6
                263, // 0x68C4 CLIMB_END  B715 [7,8]   (4<<6)+7
                265, // 0x68C5 DAMAGE_S   B72D [9..]   (4<<6)+9
                268, // 0x68C6 FREEZE     B747 [12..]  (4<<6)+12
                273, // 0x68C7 FALL_S     B761 [17,18] (4<<6)+17
                271, // 0x68C8 FALL_L     B779 [15,16] (4<<6)+15
                275, // 0x68C9 BREATH     B791 [19,23] (4<<6)+19
                279, // 0x68CA t=4 eff=23
                276, // 0x68CB t=4 eff=20
                271, // 0x68CC B7C2
                265, // 0x68CD B72D
                256, // 0x68CE B66E [0]
                259, // 0x68CF eff=3 (4<<6)+3
                283, // 0x68D0 B803 eff=27 (4<<6)+27
                261, // 0x68D1 B66E [5]
                265, // 0x68D2 fallback
                260, // 0x68D3 B66E [4]
                262, // 0x68D4 fallback
                262, // 0x68D5 B66E [6]
                268, // 0x68D6 B66E [12]
                256, 256,
                271, // 0x68D9 B779 [15,16]
                256, 256, 256, 256, 256,
            };
            effectIdx = (action < 32) ? sGoronActionToSfxId[action] : 256;
        } else {
            // Mask of Scents range (0x68E0-0x68FF). POO_WAIT verified to work at
            // (1<<6)+35 = 99 — confirming the (transpose<<6)+effect formula.
            switch (mmSfxId) {
                case 0x68E0: effectIdx = 99; break; // POO_WAIT (verified working)
                default:     effectIdx = 99; break;
            }
        }

        if (effectIdx < font0->numSfx && font0->soundEffects[effectIdx].sample &&
            font0->soundEffects[effectIdx].sample->sampleAddr) {
            sMmLastPitchScale = 1.0f; // No transpose — each form has its own samples
            {
                SoundFontSample* vs = font0->soundEffects[effectIdx].sample;
                u8* vd = (u8*)vs->sampleAddr;
                MMSFX_LOG("[MmDirectAudio] Voice 0x%04X: sfx[%d] tuning=%.4f size=%u codec=%d "
                          "first8=[%02X %02X %02X %02X %02X %02X %02X %02X]",
                          mmSfxId, effectIdx, font0->soundEffects[effectIdx].tuning, vs->size, vs->codec, vd[0], vd[1],
                          vd[2], vd[3], vd[4], vd[5], vd[6], vd[7]);
            }
            return &font0->soundEffects[effectIdx];
        }

        MMSFX_LOG("[MmDirectAudio] Voice 0x%04X: soundEffects[%d] has no valid sample (numSfx=%d)", mmSfxId, effectIdx,
                  font0->numSfx);
        return nullptr;
    }

    // =========================================================================
    // Player/Item/Environment/System/Ocarina banks:
    // SFX IDs map to specific instruments[] at specific pitches via seq_0
    // =========================================================================

    // Check the instrument mapping table first
    for (s32 i = 0; i < sMmSfxInstrMapSize; i++) {
        if (sMmSfxInstrMap[i].sfxId == mmSfxId) {
            u8 instIdx = sMmSfxInstrMap[i].instrumentIdx;
            u8 note = sMmSfxInstrMap[i].midiNote;

            // FONTANY_INSTR_DRUM (127): use font->drums[] instead of instruments[]
            // Used by TRANSFORM_VOICE (0x09AA) which plays drums[4] in seq_0
            if (instIdx == 127) {
                if (font0->drums && note < font0->numDrums && font0->drums[note]) {
                    sMmLastPitchScale = 1.0f; // Drums already have correct pitch in tuning
                    MMSFX_LOG("[MmDirectAudio] Drum 0x%04X: drums[%d]", mmSfxId, note);
                    return &font0->drums[note]->sound;
                }
                MMSFX_LOG("[MmDirectAudio] Drum 0x%04X: drums[%d] not found (numDrums=%d)", mmSfxId, note,
                          font0->numDrums);
                break;
            }

            // Use Direct version (no loaded check) — SoH factory always sets loaded=0.
            // This is safe: these are EXPLICITLY mapped sounds from our table, not random lookups.
            SoundFontSound* sound = MmDirectAudio_GetInstrumentSoundDirect(font0, instIdx, note);
            if (sound) {
                // Pitch correction: the tuning is calibrated for MIDI note 60 (middle C)
                // Adjust for the actual note
                sMmLastPitchScale = powf(2.0f, ((f32)note - 60.0f) / 12.0f);
                MMSFX_LOG("[MmDirectAudio] Mapped 0x%04X: instruments[%d], note=%d, pitch=%.3f", mmSfxId, instIdx, note,
                          sMmLastPitchScale);
                return sound;
            }
            MMSFX_LOG("[MmDirectAudio] Mapped 0x%04X: instruments[%d] exists but no valid sample", mmSfxId, instIdx);
            break;
        }
    }

    // SFX not found in instrument map - return NULL (silence).
    // DO NOT use soundEffects[sfxIndex] as fallback - SFX IDs do not map to soundEffects
    // indices for non-voice banks. The seq_0 program routes them to specific instruments
    // at specific pitches. Without a mapping entry, we'd play the wrong sound.
    MMSFX_LOG("[MmDirectAudio] No mapping for 0x%04X (bank=%d, idx=%d) - no sound", mmSfxId, bank, sfxIndex);
    return nullptr;
}

// Compute volume and pan from projected position (view-space coordinates).
// pos->x = left/right offset from camera, pos->z = depth from camera.
static void MmDirectAudio_ComputeSpatial(Vec3f* pos, f32* outVol, f32* outPan) {
    if (!pos) {
        // No position (2D sound) - full volume, center pan
        *outVol = 0.85f;
        *outPan = 0.5f;
        return;
    }

    // Distance-based volume attenuation (matches OOT's squared distance formula)
    f32 distSq = (pos->x * pos->x * 0.25f + pos->y * pos->y + pos->z * pos->z) * 0.1f;
    f32 dist = sqrtf(distSq);
    f32 maxDist = 500.0f; // Full volume within this range
    f32 vol;
    if (dist <= maxDist) {
        vol = 0.85f;
    } else {
        vol = 0.85f * (1.0f - (dist - maxDist) / (10000.0f - maxDist));
    }
    if (vol < 0.0f)
        vol = 0.0f;
    if (vol > 0.85f)
        vol = 0.85f;

    // Stereo pan from X/Z position (similar to OOT's AudioSfx_ComputePanSigned)
    f32 pan = 0.5f;
    f32 absZ = (pos->z > 0.0f) ? pos->z : -pos->z;
    if (absZ > 1.0f) {
        pan = 0.5f + (pos->x / (absZ + 100.0f)) * 0.4f;
        if (pan < 0.05f)
            pan = 0.05f;
        if (pan > 0.95f)
            pan = 0.95f;
    }

    *outVol = vol;
    *outPan = pan;
}

// =============================================================================
// Built-in Waveform: FONTANY_INSTR_TRIANGLE (129)
// =============================================================================
// MM's audio engine synthesizes triangle/sine waves on-the-fly for instruments
// 129 (triangle) and 130 (sine). We pre-generate a multi-cycle triangle wave
// buffer to play via PlaySinglePCM at the correct pitch.
// Used by: DEKUNUTS_JUMP (0x09B0-0x09B7) - the Deku hop "boing" sound.

#define FONTANY_INSTR_TRIANGLE 129
#define TRIANGLE_CYCLE_LEN 64
#define TRIANGLE_NUM_CYCLES 200
#define TRIANGLE_TOTAL_SAMPLES (TRIANGLE_CYCLE_LEN * TRIANGLE_NUM_CYCLES)
// Virtual sample rate: at C4 (261.63 Hz), one cycle = 64 samples → 261.63 * 64 = 16744
#define TRIANGLE_SAMPLE_RATE 16744
#define TRIANGLE_BASE_NOTE 60
#define TRIANGLE_AMPLITUDE 10000

static s16 sTriangleWave[TRIANGLE_TOTAL_SAMPLES];
static bool sTriangleGenerated = false;

static void MmWav_GenerateTriangle(void) {
    if (sTriangleGenerated)
        return;
    for (s32 i = 0; i < TRIANGLE_TOTAL_SAMPLES; i++) {
        s32 phase = i % TRIANGLE_CYCLE_LEN;
        s32 half = TRIANGLE_CYCLE_LEN / 2;
        if (phase < half) {
            sTriangleWave[i] = (s16)(-TRIANGLE_AMPLITUDE + (2 * TRIANGLE_AMPLITUDE * phase) / half);
        } else {
            sTriangleWave[i] = (s16)(TRIANGLE_AMPLITUDE - (2 * TRIANGLE_AMPLITUDE * (phase - half)) / half);
        }
    }
    sTriangleGenerated = true;
    MMSFX_LOG("[MmWav] Generated triangle wave: %d samples", TRIANGLE_TOTAL_SAMPLES);
}

// FONTANY_INSTR_SINE (130) — used by DEKUNUTS_DROP_BOMB (seq_0:7779). MM seqplayer.c:1167-1170
// treats instId >= 0x80 as synthetic waves. Without this, our engine fell through to instrument
// lookup which fails for idx 130 (Soundfont_0 only has 122 instruments) → SILENT playback.
#define FONTANY_INSTR_SINE 130
#define SINE_CYCLE_LEN 64
#define SINE_NUM_CYCLES 200
#define SINE_TOTAL_SAMPLES (SINE_CYCLE_LEN * SINE_NUM_CYCLES)
#define SINE_SAMPLE_RATE 16744
#define SINE_BASE_NOTE 60
#define SINE_AMPLITUDE 10000

static s16 sSineWave[SINE_TOTAL_SAMPLES];
static bool sSineGenerated = false;

static void MmWav_GenerateSine(void) {
    if (sSineGenerated)
        return;
    const f32 twoPi = 6.28318530717958647692f;
    for (s32 i = 0; i < SINE_TOTAL_SAMPLES; i++) {
        s32 phase = i % SINE_CYCLE_LEN;
        f32 angle = twoPi * (f32)phase / (f32)SINE_CYCLE_LEN;
        sSineWave[i] = (s16)(SINE_AMPLITUDE * sinf(angle));
    }
    sSineGenerated = true;
    MMSFX_LOG("[MmWav] Generated sine wave: %d samples", SINE_TOTAL_SAMPLES);
}

// Play pre-loaded PCM data (e.g. synthetic triangle wave) into a slot. Does NOT own the PCM data.
static s32 MmDirectAudio_PlaySinglePCM(s16* pcm, u32 pcmLength, f32 advance, u16 mmSfxId, f32 volume, f32 pan,
                                       f32 vibratoRate, f32 vibratoDepth) {
    if (!pcm || pcmLength == 0)
        return 0;

    // Layer limit: don't exceed 3 active layers per sfxId
    s32 existingLayers = 0;
    for (s32 i = 0; i < MM_DIRECT_MAX_SOUNDS; i++) {
        if (sPlayingSounds[i].active && sPlayingSounds[i].mmSfxId == mmSfxId)
            existingLayers++;
    }
    // Layer cap raised to 8 to accommodate sequential multi-note SFX (BUD 4 notes × 2 layers).
    // The prior cap of 3 was added to defend against runaway slot allocation when the
    // same-sfxId search loop existed; with direct-slot writes that defense is no longer needed.
    if (existingLayers >= 8)
        return 0; // Skip — return 0 (no slot allocated) so callers see this as "not played".

    // Find free slot (prefer evicting non-continuous sounds)
    s32 freeSlot = -1;
    for (s32 i = 0; i < MM_DIRECT_MAX_SOUNDS; i++) {
        if (!sPlayingSounds[i].active) {
            freeSlot = i;
            break;
        }
    }
    if (freeSlot < 0) {
        for (s32 i = 0; i < MM_DIRECT_MAX_SOUNDS; i++) {
            if (!MmDirectAudio_IsContinuous(sPlayingSounds[i].mmSfxId)) {
                freeSlot = i;
                break;
            }
        }
        if (freeSlot < 0)
            freeSlot = 0;
        if (sPlayingSounds[freeSlot].pcmData && sPlayingSounds[freeSlot].ownsPcm)
            free(sPlayingSounds[freeSlot].pcmData);
        sPlayingSounds[freeSlot].pcmData = nullptr;
        sPlayingSounds[freeSlot].active = 0;
    }

    MmPlayingSound* snd = &sPlayingSounds[freeSlot];
    if (snd->pcmData && snd->ownsPcm)
        free(snd->pcmData);

    snd->pcmData = pcm;
    snd->pcmLength = pcmLength;
    snd->pcmPosition = 0.0f;
    snd->advance = advance;
    snd->volume = volume;
    snd->pan = pan;
    snd->mmSfxId = mmSfxId;
    snd->loopStart = 0;
    snd->loopEnd = 0;
    snd->lifeSamples = 0;
    snd->maxLifeSamples = 0;
    snd->vibratoPhase = 0.0f;
    snd->vibratoRate = vibratoRate;
    snd->vibratoDepth = vibratoDepth;
    snd->portaStartAdv = 0.0f; // No portamento for WAV sounds
    snd->portaEndAdv = 0.0f;
    snd->portaProgress = 1.0f;
    snd->portaRate = 0.0f;
    snd->portaPreHoldSamples = 0;
    snd->startDelaySamples = 0;
    snd->vibratoRateEnd = 0.0f;
    snd->vibratoDepthEnd = 0.0f;
    snd->vibGradSamplesElapsed = 0;
    snd->vibGradSamplesTotal = 0;
    snd->ownsPcm = 0; // Cached WAV data - do NOT free
    snd->isContinuous = MmDirectAudio_IsContinuous(mmSfxId) ? 1 : 0;
    snd->lastRefreshFrame = sMmAudioFrame;
    snd->active = 1;

    // Apply ADSR envelope (no instrument data for cached WAV)
    MmDirectAudio_SetEnvelope(snd, snd->isContinuous);

    MMSFX_LOG("[MmWav] Playing 0x%04X: %u samples, advance=%.3f, vol=%.3f", mmSfxId, pcmLength, advance, snd->volume);
    // Return slot+1 (so 0 means failure/skip; caller decodes index as result-1).
    // Lets the dispatcher write per-entry envPreset/porta/sub-note to the EXACT slot we
    // just populated, instead of searching by sfxId — which collides when multiple layers
    // share the same sfxId (FLOWER_OPEN, BUBLE_BREATH) or when a sub-note races the main.
    return freeSlot + 1;
}

// Play a single sample into a slot. Returns 1 if played, 0 if failed.
// envelope + releaseRate come from the MM instrument (if available) for real ADSR shaping.
static s32 MmDirectAudio_PlaySingle(SoundFontSound* sfxSound, f32 pitchScale, f32 freqScale, u16 mmSfxId, f32 volume,
                                    f32 pan, f32 vibratoRate, f32 vibratoDepth) {
    if (!sfxSound || !sfxSound->sample) {
        return 0;
    }

    u32 pcmLength = 0;
    s16* pcm = MmDirectAudio_DecodeADPCM(sfxSound->sample, &pcmLength);
    if (!pcm || pcmLength == 0) {
        MMSFX_LOG("[MmDirectAudio] Decode failed for 0x%04X", mmSfxId);
        return 0;
    }

    // Find free slot — prefer reusing same sfxId slot for continuous sounds
    s32 freeSlot = -1;
    bool isContinuous = MmDirectAudio_IsContinuous(mmSfxId);

    // For multi-layer SFX: count how many layers of this sfxId are already playing.
    // Each SFX can have up to 2-3 layers. Don't exceed that.
    s32 existingLayers = 0;
    for (s32 i = 0; i < MM_DIRECT_MAX_SOUNDS; i++) {
        if (sPlayingSounds[i].active && sPlayingSounds[i].mmSfxId == mmSfxId) {
            existingLayers++;
        }
    }
    // Layer cap raised to 8 (see PCM variant comment). Sequential note chains (BUD)
    // need more slots than the legacy 3-layer-max budget.
    if (existingLayers >= 8) {
        free(pcm);
        return 0; // Skip — return 0 (no slot index produced) so caller's slot > 0 fails.
    }

    for (s32 i = 0; i < MM_DIRECT_MAX_SOUNDS; i++) {
        if (!sPlayingSounds[i].active) {
            freeSlot = i;
            break;
        }
    }
    if (freeSlot < 0) {
        // Evict oldest non-continuous sound
        for (s32 i = 0; i < MM_DIRECT_MAX_SOUNDS; i++) {
            if (!MmDirectAudio_IsContinuous(sPlayingSounds[i].mmSfxId)) {
                freeSlot = i;
                break;
            }
        }
        if (freeSlot < 0)
            freeSlot = 0; // Last resort
        if (sPlayingSounds[freeSlot].pcmData && sPlayingSounds[freeSlot].ownsPcm)
            free(sPlayingSounds[freeSlot].pcmData);
        sPlayingSounds[freeSlot].pcmData = nullptr;
        sPlayingSounds[freeSlot].active = 0;
    }

    MmPlayingSound* snd = &sPlayingSounds[freeSlot];
    if (snd->pcmData && snd->ownsPcm)
        free(snd->pcmData);

    snd->pcmData = pcm;
    snd->pcmLength = pcmLength;
    snd->pcmPosition = 0.0f;
    snd->advance = sfxSound->tuning * pitchScale * freqScale;

    // Volume attenuation for extreme pitches — prevents high-pitched screeching
    // (e.g., transform flash 0x484F at advance=3.0 becomes 67% volume)
    if (snd->advance > 2.0f) {
        volume *= (2.0f / snd->advance);
    }

    snd->volume = volume;
    snd->pan = pan;
    snd->mmSfxId = mmSfxId;

    // Loop handling: respect the sample's sustain loop ALWAYS so high-pitched
    // short samples (e.g. ShimmeringTreasure pitched +5oct for DEKUNUTS_ATTACK)
    // don't end after 49ms when MM holds the notedv for ~900ms.
    // In MM/N64, sustain loops (count=-1) are held by the ADSR envelope until the
    // notedv duration ends. We approximate that with a duration cap:
    //   - Continuous SFX (sContinuousSfxIds): no cap, play until explicit Stop
    //   - One-shot SFX with loop: auto-stop at ~1.2s (matches typical MM notedv 100-150t)
    //     The PCM keeps looping until maxLifeSamples is reached, then ADSR release kicks in
    SoundFontSample* sample = sfxSound->sample;
    bool hasLoop = sample->loop && sample->loop->count != 0 && sample->loop->loopEnd > sample->loop->start;

    if (hasLoop) {
        snd->loopStart = sample->loop->start;
        snd->loopEnd = (sample->loop->loopEnd < pcmLength) ? sample->loop->loopEnd : pcmLength;
        if (isContinuous) {
            snd->maxLifeSamples = 0; // No auto-stop
            MMSFX_LOG("[MmDirectAudio] Loop 0x%04X: %u -> %u (continuous)", mmSfxId, snd->loopStart, snd->loopEnd);
        } else {
            // One-shot with loop: cap matches MM notedv ~ release. Per-SFX overrides for
            // known cases keep flower/strike sounds from ringing too long.
            // MM tick ≈ 8ms → 100 ticks = 800ms. Most flower SFX notedv 24-30 ticks ≈ 200-250ms.
            u32 cap = 19200; // default 600ms — covers most notedv 50-80 ticks
            switch (mmSfxId) {
                // Goron BALL_CHARGE_DASH layers cap: dash impact ~300ms, NOT a sustained loop.
                // Prevents the dash sound from being mistaken for a "charging continued" loop.
                case 0x09A3: cap = 9600; break;
                // Deku spin attack: notedv 112 ticks ≈ 900ms (the iconic "wsshhh")
                case 0x09A9: cap = 28800; break;
                // Deku flower SFX — short notedv 24-30 ticks
                case 0x1850: cap = 8000; break;  // FLOWER_OPEN notedv 10+10 + 24 ≈ 250ms
                case 0x1852: cap = 8000; break;  // FLOWER_CLOSE notedv 4+24 ≈ 220ms
                case 0x09A0: cap = 30000; break; // BUD: 4-note chain with ldelay=82 ticks ≈ 656ms + 200ms decay ≈ 900ms
                case 0x09A6: cap = 5000; break;  // STRUGGLE notedv 7+9 ticks ≈ 130ms (very short flap)
                // Deku flower dive/launch: notedv 100 ticks ≈ 800ms
                case 0x08E2: cap = 25600; break; // IN_GRD ≈ 800ms
                case 0x08E3: cap = 25600; break; // OUT_GRD ≈ 800ms
                // Bubble breath / spark barrier are short impacts when not continuous
                case 0x1853: cap = 8000; break;  // BUBLE_BROKEN notedv 24 ticks
                case 0x1854: cap = 8000; break;  // BUBLE_VANISH
            }
            snd->maxLifeSamples = cap;
            MMSFX_LOG("[MmDirectAudio] Loop 0x%04X: %u -> %u (one-shot, cap=%u samples ≈ %ums)", mmSfxId,
                      snd->loopStart, snd->loopEnd, cap, cap * 1000 / 32000);
        }
    } else {
        // No loop in sample: play through once, ends when PCM exhausted
        snd->loopStart = 0;
        snd->loopEnd = 0;
        snd->maxLifeSamples = 0;
    }
    snd->lifeSamples = 0;
    snd->vibratoPhase = 0.0f;
    snd->vibratoRate = vibratoRate;
    snd->vibratoDepth = vibratoDepth;
    snd->portaStartAdv = 0.0f; // Portamento set externally after play if needed
    snd->portaEndAdv = 0.0f;
    snd->portaProgress = 1.0f; // 1.0 = no portamento active
    snd->portaRate = 0.0f;
    snd->portaPreHoldSamples = 0;
    snd->startDelaySamples = 0;
    snd->vibratoRateEnd = 0.0f;
    snd->vibratoDepthEnd = 0.0f;
    snd->vibGradSamplesElapsed = 0;
    snd->vibGradSamplesTotal = 0;
    snd->ownsPcm = 1; // ADPCM-decoded data is owned by this slot
    snd->isContinuous = isContinuous ? 1 : 0;
    snd->lastRefreshFrame = sMmAudioFrame;
    snd->active = 1;

    // Apply ADSR envelope from real MM instrument data
    MmDirectAudio_SetEnvelope(snd, isContinuous);

    MMSFX_LOG("[MmDirectAudio] Playing 0x%04X: %u samples, tuning=%.3f, pitch=%.3f, freq=%.3f, advance=%.3f, vol=%.3f, "
              "env: atk=%.4f dec=%.4f sus=%.2f rel=%.4f relAt=%u",
              mmSfxId, pcmLength, sfxSound->tuning, pitchScale, freqScale, snd->advance, snd->volume,
              snd->envAttackRate, snd->envDecayRate, snd->envSustainLevel, snd->envReleaseRate, snd->envReleaseAt);
    // Return slot+1 so the dispatcher knows EXACTLY which slot to configure.
    // The prior `return 1` boolean forced a same-sfxId scan that collided across layers.
    return freeSlot + 1;
}

// Start playing an MM sound with multi-layer support.
// Uses ONLY mm.o2r ADPCM samples (real MM sounds). No OOT WAV fallbacks.
// Returns 1 if at least one layer played, 0 if no valid sample found.
static s32 MmDirectAudio_Play(u16 mmSfxId, f32 freqScale, Vec3f* pos) {
    s32 bank = MM_SFX_BANK_INDEX(mmSfxId);
    s32 played = 0;

    // Compute volume/pan from position
    f32 vol, pan;
    MmDirectAudio_ComputeSpatial(pos, &vol, &pan);

    // =========================================================================
    // DEDUPLICATION: MM's audio engine reuses channels for the same SFX.
    // The game calls PlaySfx every frame for continuous sounds (rolling, etc.)
    // and frequently for one-shots. Without dedup, we flood all 16 slots.
    // =========================================================================
    bool isContinuous = MmDirectAudio_IsContinuous(mmSfxId);

    // For continuous sounds: refresh ALL active layers (not just the first!).
    // Multi-layer SFX (like rolling: INST_77 + INST_47) need every layer refreshed,
    // otherwise the auto-stop mechanism kills un-refreshed layers after 3 frames.
    if (isContinuous) {
        bool anyFound = false;
        for (s32 i = 0; i < MM_DIRECT_MAX_SOUNDS; i++) {
            if (sPlayingSounds[i].active && sPlayingSounds[i].mmSfxId == mmSfxId) {
                sPlayingSounds[i].volume = vol;
                sPlayingSounds[i].pan = pan;
                sPlayingSounds[i].lastRefreshFrame = sMmAudioFrame;
                // NO porta-reset on continuous refresh for any SFX. User-confirmed
                // that resetting porta on each cadence pulse (was scoped to 0x1851
                // FLOWER_ROLL) produced an audible click/glitch — each pulse forced
                // a sudden D2→D3 pitch jump on the already-playing slot.
                // MM's effective propeller character (5-tick notes barely letting
                // porta complete) is closer to "sustain at end pitch" than to
                // "re-sweep every pulse" in our 12x-faster sweep timebase.
                anyFound = true;
            }
        }
        if (anyFound)
            return 1;
    }

    // For one-shot sounds: allow re-trigger only if the previous instance
    // is in release phase or nearly done (>75% through).
    for (s32 i = 0; i < MM_DIRECT_MAX_SOUNDS; i++) {
        if (sPlayingSounds[i].active && sPlayingSounds[i].mmSfxId == mmSfxId) {
            f32 progress = sPlayingSounds[i].pcmPosition / (f32)sPlayingSounds[i].pcmLength;
            if (progress < 0.75f && sPlayingSounds[i].envPhase < ADSR_PHASE_RELEASE) {
                return 1; // Still playing, skip re-trigger
            }
        }
    }

    // =========================================================================
    // Voice bank (6): use REAL MM voice samples from Soundfont_0 via ADPCM
    // Goron/Zora/Deku/FD/HL all have their own samples in mm.o2r
    // =========================================================================
    if (bank == 6) {
        // Voice routing:
        // - Sample selection uses `(transpose<<6) + effect` formula — samples are
        //   already pre-arranged in MM SF0 by transpose-block, so this picks the
        //   form's correct sample directly. POO_WAIT (Mask of Scents, transpose=1)
        //   at index (1<<6)+35=99 was verified to play its correct sample, proving
        //   this formula. NO additional pitch shift needed — samples have correct
        //   tuning baked in.
        // - Vibrato: VERIFIED VERBATIM from mm_decomp seq_0.prg.seq:26722-26830 — the entry
        //   channels CHAN_BC5E (Deku) and CHAN_BCF3 (Zora) FALL THROUGH to CHAN_BC64 / CHAN_BCF9
        //   which set vibrato. So *EVERY* Deku voice that calls CHAN_BC5E (which is most of them)
        //   gets vibrato 128/88. Same for Zora calling CHAN_BCF3 → vibrato 240/32.
        //   Prior code only handled 4 Deku + 2 Zora explicit BC64/BCF9 callers — missed SWORD_L
        //   (0x6881) which is why Deku spin attack voice sounded dry/flat vs MM.
        //   Goron channels (CHAN_BD84/BD8A) do NOT have a vibrato fall-through.
        //   FD/Human (CHAN_B87B) does NOT have vibrato (no fall-through).
        f32 vibRate = 0.0f, vibDepth = 0.0f;

        // MM vibrato semantics (verified from mm_decomp seqplayer.c:1379 + effects.c:181):
        //   vibdepth opcode N → vib->depth = N * 8
        //   scaledDepth = vib->depth / 4096 → peak pitch modulation [0..1]
        // Final freqScale oscillates ±scaledDepth around 1.0.
        // Conversion: vibratoDepth = (mm_vibdepth * 8) / 4096 = mm_vibdepth / 512.

        if (mmSfxId >= 0x6880 && mmSfxId <= 0x689F) {
            // Deku block: all voices call CHAN_BC5E which falls through to CHAN_BC64.
            // vibdepth=88, vibfreq=128 (MM seq_0:26726-26727).
            vibRate = 128.0f * (1.0f / 16.0f);     // ~8 Hz wobble
            vibDepth = 88.0f / 512.0f;              // ~17% pitch modulation
        } else if (mmSfxId >= 0x68A0 && mmSfxId <= 0x68BF) {
            // Zora block: all voices call CHAN_BCF3 which falls through to CHAN_BCF9.
            // vibdepth=32, vibfreq=240 (MM seq_0:26828-26829). Lighter & faster than Deku.
            vibRate = 240.0f * (1.0f / 16.0f);     // 15 Hz fast wobble
            vibDepth = 32.0f / 512.0f;              // ~6% pitch modulation
        }
        // Goron (0x68C0-0x68DF), FD (0x6800-0x681F), Human (0x6820-0x683F):
        // no vibrato in MM seq_0 channel entry points → stay at 0.0f.

        // Use ADPCM from mm.o2r Soundfont_0 (real MM voice recordings).
        // No voiceTranspose multiplier — samples are stored pre-shifted at their
        // (transpose<<6)+effect index, and their tuning value is calibrated for
        // that index. Applying an extra pitch multiplier would double-shift.
        SoundFontSound* sfxSound = MmDirectAudio_GetSound(mmSfxId);
        f32 pitchScale = sMmLastPitchScale;
        if (sfxSound && sfxSound->sample) {
            return MmDirectAudio_PlaySingle(sfxSound, pitchScale, freqScale, mmSfxId, vol, pan, vibRate, vibDepth);
        }
        MMSFX_LOG("[MmDirectAudio] No sample for voice 0x%04X", mmSfxId);
        return 0;
    }

    // =========================================================================
    // Non-voice banks: multi-layer ADPCM from mm.o2r
    // =========================================================================

    // One-time diagnostic: dump ALL referenced instruments' tuning from SF0
    {
        static bool sSf0Dumped = false;
        if (!sSf0Dumped) {
            sSf0Dumped = true;
            SoundFont* dumpFont = MmSfx_LoadFont(0);
            if (dumpFont && dumpFont->instruments) {
                MMSFX_LOG("[MmSfx] ===== SF0 INSTRUMENT TUNING DUMP (numInst=%u) =====", dumpFont->numInstruments);
                u8 dumpedInst[128] = { 0 };
                for (s32 m = 0; m < sMmSfxInstrMapSize; m++) {
                    u8 idx = sMmSfxInstrMap[m].instrumentIdx;
                    if (idx >= 127 || idx >= dumpFont->numInstruments || dumpedInst[idx])
                        continue;
                    dumpedInst[idx] = 1;
                    Instrument* inst = dumpFont->instruments[idx];
                    if (!inst) {
                        MMSFX_LOG("[MmSfx]   INST[%3d] = NULL", idx);
                        continue;
                    }
                    MMSFX_LOG("[MmSfx]   INST[%3d]: rangeLo=%3d rangeHi=%3d "
                              "low(tune=%.4f samp=%p) norm(tune=%.4f samp=%p) high(tune=%.4f samp=%p)",
                              idx, inst->normalRangeLo, inst->normalRangeHi, inst->lowNotesSound.tuning,
                              (void*)inst->lowNotesSound.sample, inst->normalNotesSound.tuning,
                              (void*)inst->normalNotesSound.sample, inst->highNotesSound.tuning,
                              (void*)inst->highNotesSound.sample);
                }
                MMSFX_LOG("[MmSfx] ===== END SF0 DUMP =====");
            }
        }
    }

    for (s32 i = 0; i < sMmSfxInstrMapSize; i++) {
        if (sMmSfxInstrMap[i].sfxId != mmSfxId)
            continue;

        u8 instIdx = sMmSfxInstrMap[i].instrumentIdx;
        u8 note = sMmSfxInstrMap[i].midiNote;
        s8 transpose = sMmSfxInstrMap[i].transpose;
        u8 portaNote = sMmSfxInstrMap[i].portaNote;
        u8 portaSpeed = sMmSfxInstrMap[i].portaSpeed;
        u8 preHoldTicks = sMmSfxInstrMap[i].preHoldTicks;
        u8 entryVelocity = sMmSfxInstrMap[i].velocity;
        u8 entryGain = sMmSfxInstrMap[i].gain;
        u8 entryLDelayTicks = sMmSfxInstrMap[i].ldelayTicks;
        // (NEW) extended fields:
        u8 entryPortaModeInv = sMmSfxInstrMap[i].portaModeInv;
        u8 entryVibFreq = sMmSfxInstrMap[i].vibFreq;
        u8 entryVibDepth = sMmSfxInstrMap[i].vibDepth;
        u8 entryVibFreqEnd = sMmSfxInstrMap[i].vibFreqEnd;
        u8 entryVibDepthEnd = sMmSfxInstrMap[i].vibDepthEnd;
        u8 entryVibGradTicks = sMmSfxInstrMap[i].vibGradTicks;
        u8 entryEnvPreset = sMmSfxInstrMap[i].envPreset;
        u8 entrySubNoteDelay = sMmSfxInstrMap[i].subNoteDelayTicks;
        u8 entrySubNoteInstr = sMmSfxInstrMap[i].subNoteInstr;
        u8 entrySubNoteNote = sMmSfxInstrMap[i].subNoteNote;
        u8 entrySubNoteVel = sMmSfxInstrMap[i].subNoteVelocity;
        // MM seq tick at default tempo ≈ 16ms ≈ 256 samples at 32000 Hz output.
        u32 preHoldSamples = (u32)preHoldTicks * 256u;
        u32 startDelaySamples = (u32)entryLDelayTicks * 256u;

        // Combined entry-level volume multiplier from MM notedv velocity + channel gain:
        //   velocityScale = (velocity/127)^2  [MM effects.c:45 — squared!]
        //   gainScale     = gain / 16        [MM gain UQ4.4 where 0x10=unity]
        // Default 0 in both fields treats as unity (preserves legacy behavior).
        f32 entryVolScale = 1.0f;
        if (entryVelocity != 0 && entryVelocity != 127) {
            f32 v = (f32)entryVelocity / 127.0f;
            entryVolScale *= v * v;
        }
        if (entryGain != 0 && entryGain != 0x10) {
            entryVolScale *= (f32)entryGain / 16.0f;
        }

        // Per-entry vibrato (hoisted: triangle/sine and ADPCM all honor it).
        // Without this, JUMP's `vibfreq 240` + `vibdepthgrad 0,16,4` was a no-op
        // and BUBLE_BREATH L1's swell was flat.
        f32 instVibRateOut = (entryVibFreq != 0) ? ((f32)entryVibFreq / 16.0f) : 0.0f;
        f32 instVibDepthOut = (entryVibDepth != 0) ? ((f32)entryVibDepth / 512.0f) : 0.0f;

        if (instIdx == FONTANY_INSTR_TRIANGLE) {
            // Built-in triangle wave (used by Deku hops)
            MmWav_GenerateTriangle();
            f32 targetAdvance = ((f32)TRIANGLE_SAMPLE_RATE / 32000.0f) *
                                powf(2.0f, ((f32)note - (f32)TRIANGLE_BASE_NOTE) / 12.0f) * freqScale;
            s32 triSlotPlus1 = MmDirectAudio_PlaySinglePCM(sTriangleWave, TRIANGLE_TOTAL_SAMPLES, targetAdvance, mmSfxId,
                                                            vol * 0.6f * entryVolScale, pan, instVibRateOut,
                                                            instVibDepthOut);
            s32 triSlot = triSlotPlus1 - 1;
            // Apply envPreset, portamento (incl. portaModeInv), vibrato gradient, ldelay
            // directly on the just-allocated slot. Was previously search-by-sfxId which
            // mostly failed for triangle entries (the search predicate worked but the
            // post-play code never ran in the original triangle branch).
            if (triSlotPlus1 > 0) {
                if (entryEnvPreset != 0) {
                    MmDirectAudio_ApplyEnvPreset(&sPlayingSounds[triSlot], entryEnvPreset);
                }
                if (startDelaySamples > 0) {
                    sPlayingSounds[triSlot].startDelaySamples = startDelaySamples;
                }
                if (entryVibGradTicks > 0) {
                    sPlayingSounds[triSlot].vibratoRateEnd = (f32)entryVibFreqEnd / 16.0f;
                    sPlayingSounds[triSlot].vibratoDepthEnd = (f32)entryVibDepthEnd / 512.0f;
                    sPlayingSounds[triSlot].vibGradSamplesElapsed = 0;
                    sPlayingSounds[triSlot].vibGradSamplesTotal = (u32)entryVibGradTicks * 256u;
                }
                if (portaNote > 0 && portaSpeed > 0) {
                    f32 portaStartAdv = ((f32)TRIANGLE_SAMPLE_RATE / 32000.0f) *
                                        powf(2.0f, ((f32)portaNote - (f32)TRIANGLE_BASE_NOTE) / 12.0f) * freqScale;
                    f32 durationSamples = (f32)portaSpeed * 64.0f;
                    f32 effStart = portaStartAdv;
                    f32 effEnd = targetAdvance;
                    if (entryPortaModeInv) {
                        effStart = targetAdvance;
                        effEnd = portaStartAdv;
                    }
                    sPlayingSounds[triSlot].portaStartAdv = effStart;
                    sPlayingSounds[triSlot].portaEndAdv = effEnd;
                    sPlayingSounds[triSlot].portaProgress = 0.0f;
                    sPlayingSounds[triSlot].portaRate = 1.0f / durationSamples;
                    sPlayingSounds[triSlot].advance = effStart;
                    sPlayingSounds[triSlot].portaPreHoldSamples = preHoldSamples;
                }
            }
            // Sub-note (e.g. JUMP L1 grace→sustain on triangle): play sub-note on its own slot.
            if (triSlotPlus1 > 0 && entrySubNoteNote != 0) {
                s32 subEffNote = (s32)entrySubNoteNote + (s32)transpose;
                if (subEffNote < 0) subEffNote = 0;
                if (subEffNote > 127) subEffNote = 127;
                f32 subAdvance = ((f32)TRIANGLE_SAMPLE_RATE / 32000.0f) *
                                 powf(2.0f, ((f32)subEffNote - (f32)TRIANGLE_BASE_NOTE) / 12.0f) * freqScale;
                f32 subVolScale = entryVolScale;
                if (entrySubNoteVel != 0 && entrySubNoteVel != 127) {
                    f32 v = (f32)entrySubNoteVel / 127.0f;
                    f32 mainVelSq = (entryVelocity != 0 && entryVelocity != 127)
                                        ? ((f32)entryVelocity / 127.0f) * ((f32)entryVelocity / 127.0f)
                                        : 1.0f;
                    if (mainVelSq > 0.0001f) subVolScale = (subVolScale / mainVelSq) * (v * v);
                }
                u32 subDelay = (u32)entrySubNoteDelay * 256u;
                s32 subSlotPlus1 = MmDirectAudio_PlaySinglePCM(sTriangleWave, TRIANGLE_TOTAL_SAMPLES, subAdvance,
                                                                mmSfxId, vol * 0.6f * subVolScale, pan, instVibRateOut,
                                                                instVibDepthOut);
                if (subSlotPlus1 > 0 && subDelay > 0) {
                    sPlayingSounds[subSlotPlus1 - 1].startDelaySamples = subDelay;
                }
            }
            played += (triSlotPlus1 > 0) ? 1 : 0;
            continue;
        } else if (instIdx == FONTANY_INSTR_SINE) {
            // Built-in sine wave (130) — used by DEKUNUTS_DROP_BOMB.
            MmWav_GenerateSine();
            f32 targetAdvance = ((f32)SINE_SAMPLE_RATE / 32000.0f) *
                                powf(2.0f, ((f32)note - (f32)SINE_BASE_NOTE) / 12.0f) * freqScale;
            s32 sinSlotPlus1 = MmDirectAudio_PlaySinglePCM(sSineWave, SINE_TOTAL_SAMPLES, targetAdvance, mmSfxId,
                                                            vol * 0.6f * entryVolScale, pan, instVibRateOut,
                                                            instVibDepthOut);
            s32 sinSlot = sinSlotPlus1 - 1;
            if (sinSlotPlus1 > 0) {
                if (entryEnvPreset != 0) {
                    MmDirectAudio_ApplyEnvPreset(&sPlayingSounds[sinSlot], entryEnvPreset);
                }
                if (startDelaySamples > 0) {
                    sPlayingSounds[sinSlot].startDelaySamples = startDelaySamples;
                }
                if (entryVibGradTicks > 0) {
                    sPlayingSounds[sinSlot].vibratoRateEnd = (f32)entryVibFreqEnd / 16.0f;
                    sPlayingSounds[sinSlot].vibratoDepthEnd = (f32)entryVibDepthEnd / 512.0f;
                    sPlayingSounds[sinSlot].vibGradSamplesElapsed = 0;
                    sPlayingSounds[sinSlot].vibGradSamplesTotal = (u32)entryVibGradTicks * 256u;
                }
                if (portaNote > 0 && portaSpeed > 0) {
                    f32 portaStartAdv = ((f32)SINE_SAMPLE_RATE / 32000.0f) *
                                        powf(2.0f, ((f32)portaNote - (f32)SINE_BASE_NOTE) / 12.0f) * freqScale;
                    f32 durationSamples = (f32)portaSpeed * 16.0f;
                    f32 effStart = portaStartAdv;
                    f32 effEnd = targetAdvance;
                    if (entryPortaModeInv) {
                        effStart = targetAdvance;
                        effEnd = portaStartAdv;
                    }
                    sPlayingSounds[sinSlot].portaStartAdv = effStart;
                    sPlayingSounds[sinSlot].portaEndAdv = effEnd;
                    sPlayingSounds[sinSlot].portaProgress = 0.0f;
                    sPlayingSounds[sinSlot].portaRate = 1.0f / durationSamples;
                    sPlayingSounds[sinSlot].advance = effStart;
                    sPlayingSounds[sinSlot].portaPreHoldSamples = preHoldSamples;
                }
            }
            played += (sinSlotPlus1 > 0) ? 1 : 0;
            continue;
        } else if (instIdx == 127) { // FONTANY_INSTR_DRUM
            // ADPCM from mm.o2r Soundfont_0 (real MM drum samples)
            SoundFont* font0 = MmSfx_LoadFont(0);
            if (font0 && font0->drums && note < font0->numDrums && font0->drums[note]) {
                played += MmDirectAudio_PlaySingle(&font0->drums[note]->sound, 1.0f, freqScale, mmSfxId, vol, pan, 0.0f,
                                                   0.0f);
            }
        } else {
            // ADPCM from mm.o2r Soundfont_0 (real MM instrument samples)
            SoundFont* font0 = MmSfx_LoadFont(0);
            if (font0) {
                // Transpose: used for SAMPLE SELECTION only (range-split instruments).
                // Apply transpose to both sample selection AND pitch (matches MM seqplayer)
                s32 effectiveNote = (s32)note + (s32)transpose;
                // Clamp to valid MIDI range
                if (effectiveNote < 0)
                    effectiveNote = 0;
                if (effectiveNote > 127)
                    effectiveNote = 127;
                SoundFontSound* sound = MmDirectAudio_GetInstrumentSoundDirect(font0, instIdx, (u8)effectiveNote);
                if (sound && sound->sample) {
                    f32 pitchScale = powf(2.0f, ((f32)effectiveNote - 60.0f) / 12.0f);
                    f32 advance = sound->tuning * pitchScale * freqScale;
                    MMSFX_LOG("[MmDirectAudio] INST 0x%04X: inst[%d] note=%d t=%d eff=%d tuning=%.4f advance=%.4f",
                              mmSfxId, instIdx, note, transpose, effectiveNote, sound->tuning, advance);

                    // Per-entry vibrato hoisted above the branch (instVibRateOut/instVibDepthOut).
                    f32 instVibRate = instVibRateOut;
                    f32 instVibDepth = instVibDepthOut;

                    // Apply per-entry velocity²+gain to the spatial volume.
                    f32 entryAdjustedVol = vol * entryVolScale;
                    s32 slotPlus1 = MmDirectAudio_PlaySingle(sound, pitchScale, freqScale, mmSfxId, entryAdjustedVol, pan,
                                                              instVibRate, instVibDepth);
                    s32 slot = slotPlus1 - 1; // -1 means failure/skip; >=0 is the array index we just wrote.

                    // Apply per-entry features to the EXACT slot PlaySingle populated.
                    // Direct slot indexing prevents the same-sfxId search collision that previously
                    // let later layers clobber earlier layers' envPreset/porta/sub-note.
                    if (slotPlus1 > 0) {
                        if (entryEnvPreset != 0) {
                            MmDirectAudio_ApplyEnvPreset(&sPlayingSounds[slot], entryEnvPreset);
                        }
                        if (startDelaySamples > 0) {
                            sPlayingSounds[slot].startDelaySamples = startDelaySamples;
                        }
                        if (entryVibGradTicks > 0) {
                            sPlayingSounds[slot].vibratoRateEnd = (f32)entryVibFreqEnd / 16.0f;
                            sPlayingSounds[slot].vibratoDepthEnd = (f32)entryVibDepthEnd / 512.0f;
                            sPlayingSounds[slot].vibGradSamplesElapsed = 0;
                            sPlayingSounds[slot].vibGradSamplesTotal = (u32)entryVibGradTicks * 256u;
                        }
                    }

                    // Apply portamento if specified — same direct-slot write.
                    if (slotPlus1 > 0 && portaNote > 0 && portaSpeed > 0) {
                        s32 portaEffNote = (s32)portaNote + (s32)transpose;
                        if (portaEffNote < 0)
                            portaEffNote = 0;
                        if (portaEffNote > 127)
                            portaEffNote = 127;
                        f32 portaStartPitch = powf(2.0f, ((f32)portaEffNote - 60.0f) / 12.0f);
                        f32 portaStartAdv = sound->tuning * portaStartPitch * freqScale;
                        // MM verbatim porta-time scale (seqplayer.c:950):
                        //   speed = 0x20000 / (portaTime * updatesPerFrame)   ; updatesPerFrame=4
                        // For portaTime=255 → speed=128 per audio update at 240Hz tick rate, sweep
                        // completes in ~1.05s. SOH's default `portaSpeed*16.0f` = 85ms for the same
                        // input = 12.4x too fast. Most porta-using SFX in our bank are tuned around
                        // the 85ms timing and sound right, so we keep that as the default. Per-SFX
                        // overrides bring specific cases back to MM verbatim timing:
                        //   0x09A1 BUBLE_BREATH — AF2→A3 sweep in MM is a slow swell tied to the
                        //                          envelope C018 charge-up. At 85ms our sweep
                        //                          spikes the pitch up too sharp (user-reported
                        //                          "demasiado agudo / vibrato fuera de control").
                        f32 portaTimeScale = 16.0f;
                        if (mmSfxId == 0x09A1) {
                            portaTimeScale = 200.0f; // ~12x slower → matches MM ~1.05s sweep
                        }
                        f32 durationSamples = (f32)portaSpeed * portaTimeScale;
                        // Portamento direction: MM modes 0x82, 0x84 (or our portaModeInv=1)
                        // glide INVERSE (target→start) instead of normal start→target.
                        f32 effStart = portaStartAdv;
                        f32 effEnd = advance;
                        if (entryPortaModeInv) {
                            effStart = advance;
                            effEnd = portaStartAdv;
                        }
                        sPlayingSounds[slot].portaStartAdv = effStart;
                        sPlayingSounds[slot].portaEndAdv = effEnd;
                        sPlayingSounds[slot].portaProgress = 0.0f;
                        sPlayingSounds[slot].portaRate = 1.0f / durationSamples;
                        sPlayingSounds[slot].advance = effStart;
                        sPlayingSounds[slot].portaPreHoldSamples = preHoldSamples;
                        MMSFX_LOG("[MmDirectAudio] Porta 0x%04X: startNote=%d→endNote=%d adv=%.4f→%.4f "
                                  "dur=%.0f preHold=%u",
                                  mmSfxId, (s32)portaNote, (s32)note, portaStartAdv, advance, durationSamples,
                                  (u32)preHoldSamples);
                    }

                    // Set max duration for one-shot SFX that use INST_47 (explosion1)
                    // INST_47 samples are long. In MM, seq_0 uses short note durations + releaserate
                    // to cut them. Without that, they ring forever in our system.
                    // 1 seq tick ≈ 20ms, 32kHz → 640 samples/tick.
                    // FIX: also cap INST_47 even for continuous SFX (GORON_ROLL 0x0990,
                    // GORON_CHG_ROLL 0x0980) — those re-trigger every tumble cycle but the
                    // INST_47 layer plays one notedv (40 ticks ≈ 800ms) once, not continuously.
                    // Without this cap, the Explosion1 sample (PCM 5.5sec) plays as a sustained
                    // rumble layered on top of the rolling — the "otro sonido" user reports.
                    if (slotPlus1 > 0 && instIdx == 47) {
                        u32 maxLife = 35200; // default 55 ticks = 1.1s for INST_47
                        if (mmSfxId == 0x08E7)
                            maxLife = 22400; // BALL_TO_GORON: 35 ticks
                        if (mmSfxId == 0x08EF)
                            maxLife = 22400; // SQUAT: 35 ticks
                        if (mmSfxId == 0x0990 || mmSfxId == 0x0980)
                            maxLife = 12800; // ROLL / CHG_ROLL: 400ms (one impact per tumble)
                        if (mmSfxId == 0x09A3)
                            maxLife = 9600;  // BALL_CHARGE_DASH: 300ms — dash impact must be brief
                        // 0x08E2 / 0x08E3: don't override — PlaySingle's per-sfx cap (25600)
                        // already matches MM's notedv 100t. INST_47 cap here applies only when
                        // PlaySingle's switch doesn't catch it (other INST_47 SFX).
                        sPlayingSounds[slot].maxLifeSamples = maxLife;
                    }
                    // RJUMP LOOP SIMULATION reverted: the forced loop at 48ms re-attacks
                    // the sample's loud attack portion 20 times/second without re-triggering
                    // the envelope. Result: a saturated buzz/drone — opposite of the rapid
                    // "tk-tk" MM intends (which needs envelope re-attack per re-trigger,
                    // not just PCM wrap). Proper fix requires engine support for per-layer
                    // retrigger-with-envelope, not a simple loop wrap.
                    // INST_77 (MechanicalRampUp/SAMPLE_0_391) cap — applies even for
                    // continuous SFX. MM seq plays INST_77 with finite notedv durations
                    // (no rjump in single-layer); the sample's natural sustain loop is
                    // bounded by MM's notedv end. Without this cap, our continuous
                    // semantic lets the sample loop FOREVER, producing a mechanical hum
                    // that user reports as "another loop that doesn't stop" alongside
                    // the proper rolling sound. Per-SFX caps match MM notedv:
                    //   GORON_ROLL L1 = LAYER_13DB notedv BF3 40 ticks ≈ 320ms
                    //   GORON_CHG_ROLL has rjump (LAYER_3ACC) — TRUE loop, no cap.
                    if (slotPlus1 > 0 && instIdx == 77 && mmSfxId == 0x0990) {
                        u32 maxLife = 10240; // 40 ticks ≈ 320ms — matches MM notedv
                        sPlayingSounds[slot].maxLifeSamples = maxLife;
                    }

                    // (NEW) Sub-note: an additional note that fires AFTER the main note with
                    // a tick-based delay. Implements MM's multi-note layer sequences like
                    // `notedv F4, 4, 100; notedv B4, 24, 100` (FLOWER_CLOSE, BUD, etc.).
                    // Reuses startDelaySamples infrastructure — sub-note plays in its own
                    // slot with delayed start so it overlaps/follows the main note as MM does.
                    if (slotPlus1 > 0 && entrySubNoteNote != 0) {
                        u8 subInstIdx = (entrySubNoteInstr != 0) ? entrySubNoteInstr : instIdx;
                        s32 subEffNote = (s32)entrySubNoteNote + (s32)transpose;
                        if (subEffNote < 0) subEffNote = 0;
                        if (subEffNote > 127) subEffNote = 127;
                        SoundFontSound* subSound = MmDirectAudio_GetInstrumentSoundDirect(
                            font0, subInstIdx, (u8)subEffNote);
                        if (subSound && subSound->sample) {
                            f32 subPitchScale = powf(2.0f, ((f32)subEffNote - 60.0f) / 12.0f);
                            f32 subVolScale = entryVolScale;
                            if (entrySubNoteVel != 0 && entrySubNoteVel != 127) {
                                f32 v = (f32)entrySubNoteVel / 127.0f;
                                f32 mainVelSq = (entryVelocity != 0 && entryVelocity != 127)
                                                    ? ((f32)entryVelocity / 127.0f) * ((f32)entryVelocity / 127.0f)
                                                    : 1.0f;
                                if (mainVelSq > 0.0001f) subVolScale = (subVolScale / mainVelSq) * (v * v);
                            }
                            f32 subVol = vol * subVolScale;
                            u32 subDelay = (u32)entrySubNoteDelay * 256u;
                            s32 subSlotPlus1 = MmDirectAudio_PlaySingle(subSound, subPitchScale, freqScale, mmSfxId,
                                                                        subVol, pan, instVibRate, instVibDepth);
                            if (subSlotPlus1 > 0) {
                                // Sub-note inherits the entry's envPreset — otherwise the sub stays
                                // on the default flat-sustain envelope while the main note has the
                                // intended ADSR shape (FIRE pffft, FLOWER_CLOSE swell, etc.).
                                if (entryEnvPreset != 0) {
                                    MmDirectAudio_ApplyEnvPreset(&sPlayingSounds[subSlotPlus1 - 1], entryEnvPreset);
                                }
                                // Write startDelaySamples directly — the prior same-sfxId search
                                // matched the MAIN slot first, inverting MM's grace→sustain order.
                                if (subDelay > 0) {
                                    sPlayingSounds[subSlotPlus1 - 1].startDelaySamples = subDelay;
                                }
                            }
                        }
                    }

                    played += (slotPlus1 > 0) ? 1 : 0;
                } else {
                    MMSFX_LOG("[MmDirectAudio] INST 0x%04X: inst[%d] note=%d → NO VALID SOUND (sound=%p)", mmSfxId,
                              instIdx, note, (void*)sound);
                }
            }
        }
        // Continue scanning for more layers
    }

    if (played == 0) {
        MMSFX_LOG("[MmDirectAudio] No mapping for 0x%04X (bank=%d) - no sound", mmSfxId, bank);
    }
    return played > 0 ? 1 : 0;
}

// =============================================================================
// Gakki (Instrument) Audio - Play MM instrument notes from form-specific soundfonts
// Goron Drums → Soundfont_38, Zora Guitar → Soundfont_29, Deku Pipes → Soundfont_34
// From 2Ship z64ocarina.h: OCARINA_INSTRUMENT_GORON_DRUMS/ZORA_GUITAR/DEKU_PIPES
// =============================================================================

// Load the instrument for each MM form's musical instrument.
// Zora Guitar and Deku Pipes work from Soundfont_0 (empirically verified):
//   Zora Guitar → Soundfont_0 instruments[93]
//   Deku Pipes  → Soundfont_0 instruments[94]
// Goron Drums uses dedicated Soundfont_38 (SampleBank_2: GoronDrum, BassSlap, TomDrum, etc.)
//   because Soundfont_0's inst[107] doesn't have real drum samples.
static SoundFont* MmGakki_LoadFormFont(s32 form, u8* outInstIdx) {
    if (form == 1) {
        // Goron Drums → Soundfont_38 (dedicated, has real GoronDrum samples)
        SoundFont* font = MmSfx_LoadFont(38);
        if (!font || !font->instruments || font->numInstruments == 0)
            return NULL;
        // SF38 inst[0] = GoronDrum (main drum sound)
        *outInstIdx = 0;
        MMSFX_LOG("[MmGakki] form=1 (Goron) → Soundfont_38 inst[0]");
        return font;
    }

    // Zora Guitar and Deku Pipes use Soundfont_0
    switch (form) {
        case 2:
            *outInstIdx = 93;
            break; // Zora Guitar (verified working)
        case 3:
            *outInstIdx = 94;
            break; // Deku Pipes  (verified working)
        default:
            return NULL;
    }

    SoundFont* font = MmSfx_LoadFont(0);
    if (!font || !font->instruments || *outInstIdx >= font->numInstruments)
        return NULL;

    Instrument* inst = font->instruments[*outInstIdx];
    if (!inst) {
        MMSFX_LOG("[MmGakki] Soundfont_0 instruments[%d] is NULL", *outInstIdx);
        return NULL;
    }

    MMSFX_LOG("[MmGakki] form=%d → Soundfont_0 inst[%d]", form, *outInstIdx);
    return font;
}

// Ocarina button → MIDI note mapping (from 2Ship code_8019AF00.c / z64ocarina.h)
// A=D4(62), CDown=F4(65), CRight=A4(69), CLeft=B4(71), CUp=D5(74)
static const u8 sOcarinaButtonToMidi[5] = { 62, 65, 69, 71, 74 };

// RAII scoped lock over the audio thread's mutex (via OTRGlobals accessors). Held by
// the MM SFX game-thread entry points while they mutate state the mixer reads on the
// audio thread. The mixer runs inside AudioMgr_CreateNextAudioBuffer while
// OTRAudio_Thread holds this same mutex, so taking it here serializes the two sides.
// These entry points run ONLY on the game thread and never call back into the mixer,
// so there is no re-entrancy or lock-ordering cycle. (Defined here, before first use.)
struct MmAudioScopedLock {
    MmAudioScopedLock() {
        OTRAudio_LockMutex();
    }
    ~MmAudioScopedLock() {
        OTRAudio_UnlockMutex();
    }
    MmAudioScopedLock(const MmAudioScopedLock&) = delete;
    MmAudioScopedLock& operator=(const MmAudioScopedLock&) = delete;
};

// Forward declaration (defined later in file)
static void MmDirectAudio_StopById(u16 mmSfxId);

// Play an instrument note for the current MM form
// form: MM_PLAYER_FORM_GORON(1), ZORA(2), DEKU(3)
// buttonIndex: 0=A, 1=CDown, 2=CRight, 3=CLeft, 4=CUp (from OOT sCurOcarinaBtnIdx / lastOcaNoteIdx)
// pos: world position for spatial audio
void MmGakki_PlayNote(s32 form, u8 buttonIndex, Vec3f* pos) {
    // Serialize sPlayingSounds mutation against the mixer (MmDirectAudio_MixInto,
    // audio thread). The whole body is locked so the stop+start happen atomically
    // w.r.t. the mixer; the resource-manager calls below (LoadFormFont /
    // GetInstrumentSoundDirect) do NOT take this mutex, so there is no lock-order
    // cycle. Ocarina notes are user-paced, so the brief hold is harmless.
    MmAudioScopedLock audioLock;

    // Stop previous gakki note before playing new one
    MmDirectAudio_StopById(MM_GAKKI_SFXID);

    if (buttonIndex >= 5) {
        MMSFX_LOG("[MmGakki] PlayNote: invalid buttonIndex=%d", buttonIndex);
        return;
    }

    // Load the dedicated instrument soundfont for this form (SF29/34/38).
    u8 instIdx = 0;
    SoundFont* font = MmGakki_LoadFormFont(form, &instIdx);
    if (!font) {
        MMSFX_LOG("[MmGakki] PlayNote: no valid font for form=%d", form);
        return;
    }

    u8 midiNote = sOcarinaButtonToMidi[buttonIndex];

    // Get the instrument sound, skipping loaded check (factory always sets loaded=0).
    SoundFontSound* sound = MmDirectAudio_GetInstrumentSoundDirect(font, instIdx, midiNote);
    if (!sound || !sound->sample) {
        MMSFX_LOG("[MmGakki] PlayNote: no sound for form=%d note=%d (sound=%p)", form, midiNote, sound);
        return;
    }

    // Pitch = tuning × note ratio (from MM synthesis.c)
    f32 pitchScale = powf(2.0f, ((f32)midiNote - 60.0f) / 12.0f);

    f32 vol, pan;
    MmDirectAudio_ComputeSpatial(pos, &vol, &pan);

    MMSFX_LOG("[MmGakki] PlayNote: form=%d inst[%d] btn=%d midi=%d pitch=%.3f tuning=%.3f vol=%.2f", form, instIdx,
              buttonIndex, midiNote, pitchScale, sound->tuning, vol);
    MmDirectAudio_PlaySingle(sound, pitchScale, 1.0f, MM_GAKKI_SFXID, vol, pan, 0.0f, 0.0f);
}

// MM SFX engine tick (mirrors 2Ship code_8019AF00.c:3680-3682).
// Implemented in soh/mods/sound_translator/mm_audio_sfx.cpp.
extern "C" void AudioMmSfx_ProcessRequests(void);
extern "C" void AudioMmSfx_ProcessActiveSfx(void);

// Mix all active MM sounds into the output buffer (called from audio thread)
// outBuf: interleaved stereo s16 [L0,R0,L1,R1,...], numSamples = stereo pairs
// ---- Ruta B: isolated MM SFX synth bridge --------------------------------
// Expose MmDirectAudio's proven whole-sample VADPCM decoder to the new engine's
// backend (mm_sfx_synth_backend.cpp), and pull in its audio-thread render entry.
extern "C" short* MmSfxDecode_Sample(void* sample, unsigned int* outLen) {
    return MmDirectAudio_DecodeADPCM((SoundFontSample*)sample, (u32*)outLen);
}
extern "C" void MmSfxSynth_RenderInto(short* outBuf, unsigned int numSamples);
extern "C" int MmSfx_IsGamePaused(void); // mm_player_form.cpp

void MmDirectAudio_MixInto(s16* outBuf, u32 numSamples) {
    // Silence ALL MM SFX (old MmDirectAudio bank + new mmsfx engine) while the
    // pause/kaleido screen is up — they kept playing because they don't run on a
    // SoH seq player that SoH's own pause handling would stop.
    if (MmSfx_IsGamePaused()) {
        return;
    }

    sMmAudioFrame++;

    // Drive the MM SFX bank engine each audio callback. Equivalent to 2Ship's
    // per-frame AudioSfx_ProcessRequests + AudioSfx_ProcessActiveSfx call pair.
    // Runs at ~audio-callback rate which is close enough to MM's 20-30 fps
    // tick for freshness/eviction timing.
    AudioMmSfx_ProcessRequests();
    AudioMmSfx_ProcessActiveSfx();

    // Ruta B: render the isolated MM SFX sequence engine on top of the output.
    // No-op until MmSfxSynth_Init() has loaded Sequence_0/Soundfont_0/1 (lazy,
    // triggered from the game thread in MmSfx_PlayAtPos).
    MmSfxSynth_RenderInto(outBuf, numSamples);

    // Apply SoH master volume (gSettings.Volume.Master, 0-100, default 40)
    f32 masterVol = (f32)CVarGetInteger("gSettings.Volume.Master", 40) / 100.0f;

    // Auto-stop continuous sounds that haven't been refreshed by game code.
    // In MM, continuous SFX must be re-triggered every frame via Audio_PlaySfxGeneral.
    // If the game stops calling it (e.g., player stops rolling), the sound stops.
    // We give 3 frames of grace (mixer runs ~20x/sec, game runs ~20fps).
    for (s32 slot = 0; slot < MM_DIRECT_MAX_SOUNDS; slot++) {
        MmPlayingSound* snd = &sPlayingSounds[slot];
        if (snd->active && snd->isContinuous && sMmAudioFrame > snd->lastRefreshFrame + 3) {
            // Trigger release phase (fade out) instead of instant kill
            if (snd->envPhase < ADSR_PHASE_RELEASE) {
                snd->envPhase = ADSR_PHASE_RELEASE;
                snd->envReleaseRate = 1.0f / 640.0f; // ~20ms fade-out
            }
        }
    }

    for (s32 slot = 0; slot < MM_DIRECT_MAX_SOUNDS; slot++) {
        MmPlayingSound* snd = &sPlayingSounds[slot];
        if (!snd->active || !snd->pcmData)
            continue;

        for (u32 i = 0; i < numSamples; i++) {
            // (NEW) Layer start delay (MM `ldelay N` opcode, seqplayer.c:1031): emit
            // silence and decrement the counter until the layer's scheduled start.
            // This lets multi-layer SFX produce MM's intended cascading attack pattern
            // (thud → ring → tail with ldelay 7 etc.) instead of slamming all layers
            // simultaneously which produces flam/comb artifacts.
            if (snd->startDelaySamples > 0) {
                outBuf[i * 2]     += 0; // silence
                outBuf[i * 2 + 1] += 0;
                snd->startDelaySamples--;
                continue;
            }

            // === ADSR Envelope Processing ===
            // Advance envelope state machine (per output sample, like N64 synthesis.c)
            switch (snd->envPhase) {
                case ADSR_PHASE_ATTACK:
                    snd->envVolume += snd->envAttackRate;
                    if (snd->envVolume >= 1.0f) {
                        snd->envVolume = 1.0f;
                        snd->envPhase = ADSR_PHASE_DECAY;
                    }
                    break;
                case ADSR_PHASE_DECAY:
                    snd->envVolume -= snd->envDecayRate;
                    if (snd->envVolume <= snd->envSustainLevel) {
                        snd->envVolume = snd->envSustainLevel;
                        snd->envPhase = ADSR_PHASE_SUSTAIN;
                    }
                    break;
                case ADSR_PHASE_SUSTAIN:
                    // Check if we should transition to release
                    if (snd->envReleaseAt > 0 && snd->lifeSamples + i >= snd->envReleaseAt) {
                        snd->envPhase = ADSR_PHASE_RELEASE;
                    }
                    break;
                case ADSR_PHASE_RELEASE:
                    snd->envVolume -= snd->envReleaseRate;
                    if (snd->envVolume <= 0.0f) {
                        snd->envVolume = 0.0f;
                        snd->active = 0;
                        break;
                    }
                    break;
            }

            if (!snd->active)
                break;

            // Effective volume = base volume × envelope × master volume
            f32 effVol = snd->volume * snd->envVolume * masterVol;
            f32 volL = effVol * (1.0f - snd->pan);
            f32 volR = effVol * snd->pan;

            u32 pos = (u32)snd->pcmPosition;
            if (snd->pcmLength < 2 || pos >= snd->pcmLength - 2) {
                // Check if this sound should loop
                if (snd->loopEnd > snd->loopStart) {
                    snd->pcmPosition = (f32)snd->loopStart;
                    pos = snd->loopStart;
                } else {
                    snd->active = 0;
                    break;
                }
            }

            // Loop wrap: if we've passed loopEnd, wrap to loopStart
            if (snd->loopEnd > snd->loopStart && pos >= snd->loopEnd) {
                snd->pcmPosition = (f32)snd->loopStart + (snd->pcmPosition - (f32)snd->loopEnd);
                pos = (u32)snd->pcmPosition;
                if (pos >= snd->pcmLength - 2) {
                    snd->active = 0;
                    break;
                }
            }

            // Linear interpolation between adjacent samples
            f32 frac = snd->pcmPosition - (f32)pos;
            f32 sample = snd->pcmData[pos] * (1.0f - frac) + snd->pcmData[pos + 1] * frac;

            s32 outL = outBuf[i * 2] + (s32)(sample * volL);
            s32 outR = outBuf[i * 2 + 1] + (s32)(sample * volR);

            if (outL > 32767)
                outL = 32767;
            if (outL < -32768)
                outL = -32768;
            if (outR > 32767)
                outR = 32767;
            if (outR < -32768)
                outR = -32768;

            outBuf[i * 2] = (s16)outL;
            outBuf[i * 2 + 1] = (s16)outR;

            // Apply portamento: interpolate advance rate from start to end
            f32 advance = snd->advance;
            if (snd->portaProgress < 1.0f) {
                // (NEW) Pre-hold phase: keep advance at portaStartAdv (the held
                // pre-note pitch) for portaPreHoldSamples output samples before
                // letting the glide begin. Matches MM's seq pattern where a
                // `notedv portaNote, ticks, vol` plays the start pitch for a
                // measured duration BEFORE the porta-to-target note follows.
                if (snd->portaPreHoldSamples > 0) {
                    advance = snd->portaStartAdv;
                    snd->portaPreHoldSamples--;
                } else {
                    advance = snd->portaStartAdv + (snd->portaEndAdv - snd->portaStartAdv) * snd->portaProgress;
                    snd->portaProgress += snd->portaRate;
                    if (snd->portaProgress >= 1.0f) {
                        snd->portaProgress = 1.0f;
                        snd->advance = snd->portaEndAdv; // Lock at target pitch
                        advance = snd->portaEndAdv;
                    }
                }
            }

            // Vibrato — with optional gradient. `vibratoRate`/`vibratoDepth` hold the START
            // values (never mutated); the gradient lerps toward `vibratoRateEnd`/`DepthEnd`
            // over `vibGradSamplesTotal` samples. Computed into LOCALS so we don't compound.
            f32 curVibRate = snd->vibratoRate;
            f32 curVibDepth = snd->vibratoDepth;
            if (snd->vibGradSamplesTotal > 0) {
                f32 t = (f32)snd->vibGradSamplesElapsed / (f32)snd->vibGradSamplesTotal;
                if (t > 1.0f) t = 1.0f;
                curVibRate = snd->vibratoRate + (snd->vibratoRateEnd - snd->vibratoRate) * t;
                curVibDepth = snd->vibratoDepth + (snd->vibratoDepthEnd - snd->vibratoDepth) * t;
                if (snd->vibGradSamplesElapsed < snd->vibGradSamplesTotal) {
                    snd->vibGradSamplesElapsed++;
                }
            }

            // Apply vibrato: modulate advance rate with sine LFO
            if (curVibRate > 0.0f) {
                snd->vibratoPhase += curVibRate / 32000.0f;
                if (snd->vibratoPhase >= 1.0f)
                    snd->vibratoPhase -= 1.0f;
                f32 vibMod = sinf(snd->vibratoPhase * 6.2831853f) * curVibDepth;
                advance *= (1.0f + vibMod);
            }
            snd->pcmPosition += advance;
        }

        // Update lifetime counter after processing this buffer
        snd->lifeSamples += numSamples;

        // Auto-stop after maxLifeSamples (triggers release fade-out)
        if (snd->maxLifeSamples > 0 && snd->lifeSamples >= snd->maxLifeSamples && snd->envPhase < ADSR_PHASE_RELEASE) {
            snd->envPhase = ADSR_PHASE_RELEASE;
            snd->envReleaseRate = 1.0f / 640.0f; // ~20ms fade-out
        }
    }
}

// Stop a specific MM sound (triggers release phase for smooth fade-out)
static void MmDirectAudio_StopById(u16 mmSfxId) {
    for (s32 i = 0; i < MM_DIRECT_MAX_SOUNDS; i++) {
        if (sPlayingSounds[i].active && sPlayingSounds[i].mmSfxId == mmSfxId) {
            // HARD STOP: previous behavior used a 10ms release fade, but for
            // continuous looped SFX like BALL_CHARGE the slot could survive
            // long enough for the next PlayAtPos refresh (which is racey with
            // the game thread) to inadvertently reset volume back to full.
            // Setting active=0 + envVolume=0 IMMEDIATELY kills the mix output
            // even mid-loop. The 10ms fade was inaudible anyway because most
            // SFX samples have a few zero-crossings near loop boundaries.
            sPlayingSounds[i].envVolume = 0.0f;
            sPlayingSounds[i].envPhase = ADSR_PHASE_RELEASE;
            sPlayingSounds[i].active = 0;
        }
    }
}

// Stop all MM sounds and free PCM buffers
void MmDirectAudio_StopAll(void) {
    for (s32 i = 0; i < MM_DIRECT_MAX_SOUNDS; i++) {
        sPlayingSounds[i].active = 0;
        if (sPlayingSounds[i].pcmData) {
            if (sPlayingSounds[i].ownsPcm)
                free(sPlayingSounds[i].pcmData);
            sPlayingSounds[i].pcmData = nullptr;
        }
    }
}

// =============================================================================
// MmSfx Public API (unchanged interface, new direct audio backend)
// =============================================================================

s32 MmSfx_PlayAtPos(u16 sfxId, Vec3f* pos) {
    return MmSfx_PlayEx(sfxId, pos, 4, nullptr, nullptr, nullptr);
}

extern "C" int MmSfxSynth_Init(void); // mm_sfx_synth_loader.cpp (Ruta B)

s32 MmSfx_PlayEx(u16 sfxId, Vec3f* pos, u8 token, f32* freqScale, f32* vol, s8* reverbAdd) {
    static s32 sDiagDone = 0;

    if (!MmAssets_IsAvailable()) {
        if (!sDiagDone) {
            MMSFX_LOG("[MmSfx] DIAG: MmAssets_IsAvailable() = FALSE. MM audio disabled.");
            sDiagDone = 1;
        }
        return 0;
    }

    // Boot the isolated MM SFX engine on the GAME thread (loads Sequence_0 +
    // Soundfont_0/1 via ResourceMgr — must NOT run on the audio thread).
    // Idempotent; once ready it becomes the sole SFX path (the old MmDirectAudio
    // hand-map is dead). No CVar — the new engine is the default and only path.
    MmSfxSynth_Init();

    // One-time diagnostic: enumerate mm.o2r audio resources and verify Soundfont_0
    if (!sDiagDone) {
        sDiagDone = 1;

        // STEP 1: List what audio font resources actually exist in mm.o2r
        MMSFX_LOG("[MmSfx] DIAG: ===== MM AUDIO RESOURCE ENUMERATION =====");
        if (sMmArchive) {
            try {
                auto fontFiles = sMmArchive->ListFiles("audio/fonts*");
                if (fontFiles && fontFiles->size() > 0) {
                    MMSFX_LOG("[MmSfx] DIAG: Found %zu audio font resources in mm.o2r:", fontFiles->size());
                    int shown = 0;
                    for (auto& entry : *fontFiles) {
                        if (shown < 10) {
                            MMSFX_LOG("[MmSfx] DIAG:   [%d] '%s'", shown, entry.second.c_str());
                        }
                        shown++;
                    }
                    if (shown > 10) {
                        MMSFX_LOG("[MmSfx] DIAG:   ... and %d more", shown - 10);
                    }
                } else {
                    MMSFX_LOG("[MmSfx] DIAG: NO 'audio/fonts*' found in mm.o2r! Trying broader search...");
                    auto audioFiles = sMmArchive->ListFiles("audio*");
                    if (audioFiles && audioFiles->size() > 0) {
                        MMSFX_LOG("[MmSfx] DIAG: Found %zu 'audio*' resources in mm.o2r:", audioFiles->size());
                        int shown = 0;
                        for (auto& entry : *audioFiles) {
                            if (shown < 15) {
                                MMSFX_LOG("[MmSfx] DIAG:   [%d] '%s'", shown, entry.second.c_str());
                            }
                            shown++;
                        }
                        if (shown > 15) {
                            MMSFX_LOG("[MmSfx] DIAG:   ... and %d more", shown - 15);
                        }
                    } else {
                        MMSFX_LOG("[MmSfx] DIAG: NO 'audio*' resources found in mm.o2r at all!");
                        // Last resort: list ALL resources to see what's in the archive
                        auto allFiles = sMmArchive->ListFiles();
                        if (allFiles && allFiles->size() > 0) {
                            MMSFX_LOG("[MmSfx] DIAG: mm.o2r has %zu total resources. First 15:", allFiles->size());
                            int shown = 0;
                            for (auto& entry : *allFiles) {
                                if (shown < 15) {
                                    MMSFX_LOG("[MmSfx] DIAG:   [%d] '%s'", shown, entry.second.c_str());
                                }
                                shown++;
                            }
                        } else {
                            MMSFX_LOG("[MmSfx] DIAG: mm.o2r appears EMPTY or ListFiles() failed!");
                        }
                    }
                }
            } catch (const std::exception& e) {
                MMSFX_LOG("[MmSfx] DIAG: Exception listing mm.o2r: %s", e.what());
            } catch (...) { MMSFX_LOG("[MmSfx] DIAG: Unknown exception listing mm.o2r"); }
        } else {
            MMSFX_LOG("[MmSfx] DIAG: sMmArchive is NULL! Cannot enumerate mm.o2r resources.");
        }

        // STEP 2: Try to load Soundfont_0 and verify its contents
        MMSFX_LOG("[MmSfx] DIAG: ===== SOUNDFONT_0 LOAD TEST =====");
        MMSFX_LOG("[MmSfx] DIAG: Attempting path: '%s'", "audio/fonts/Soundfont_0");
        SoundFont* font = MmSfx_LoadFont(0);
        if (!font) {
            MMSFX_LOG("[MmSfx] DIAG: Soundfont_0 FAILED to load from mm.o2r!");
            MMSFX_LOG("[MmSfx] DIAG: This means the audio font path format is WRONG or the resource doesn't exist.");
        } else {
            MMSFX_LOG("[MmSfx] DIAG: Soundfont_0 loaded OK: %u instruments, %u sfx, %u drums", font->numInstruments,
                      font->numSfx, font->numDrums);
            // Check instruments pointer validity
            MMSFX_LOG("[MmSfx] DIAG: instruments=%p, soundEffects=%p, drums=%p", (void*)font->instruments,
                      (void*)font->soundEffects, (void*)font->drums);

            // Check if instrument 47 (Goron curl) has valid data
            if (font->instruments && 47 < font->numInstruments && font->instruments[47]) {
                Instrument* inst = font->instruments[47];
                MMSFX_LOG("[MmSfx] DIAG: instruments[47] OK: loaded=%d, rangeLo=%d, rangeHi=%d", inst->loaded,
                          inst->normalRangeLo, inst->normalRangeHi);
                if (inst->normalNotesSound.sample && inst->normalNotesSound.sample->sampleAddr) {
                    MMSFX_LOG("[MmSfx] DIAG: instruments[47].normalNotesSound: sample=%p, addr=%p, tuning=%.3f",
                              (void*)inst->normalNotesSound.sample, (void*)inst->normalNotesSound.sample->sampleAddr,
                              inst->normalNotesSound.tuning);
                } else {
                    MMSFX_LOG("[MmSfx] DIAG: instruments[47].normalNotesSound.sample is NULL or has no addr!");
                }
            } else {
                MMSFX_LOG("[MmSfx] DIAG: instruments[47] NOT accessible (instruments=%p, numInst=%u)",
                          (void*)font->instruments, font->numInstruments);
            }
            // Check soundEffects[0] (human Link voice)
            if (font->soundEffects && font->numSfx > 0) {
                if (font->soundEffects[0].sample && font->soundEffects[0].sample->sampleAddr) {
                    MMSFX_LOG("[MmSfx] DIAG: soundEffects[0] OK: sample=%p, addr=%p, tuning=%.3f",
                              (void*)font->soundEffects[0].sample, (void*)font->soundEffects[0].sample->sampleAddr,
                              font->soundEffects[0].tuning);
                } else {
                    MMSFX_LOG("[MmSfx] DIAG: soundEffects[0] has no valid sample!");
                }
            } else {
                MMSFX_LOG("[MmSfx] DIAG: soundEffects NOT accessible (ptr=%p, numSfx=%u)", (void*)font->soundEffects,
                          font->numSfx);
            }
        }
        // STEP 3: Verify sample data identity — dump first 8 bytes and size of known samples
        // to confirm whether they come from MM or OOT
        if (font) {
            MMSFX_LOG("[MmSfx] DIAG: ===== SAMPLE DATA IDENTITY CHECK =====");
            // Check instrument 47 (explosion1.wav in MM, something else in OOT)
            u8 checkInsts[] = { 0, 4, 9, 27, 47, 64, 68 };
            for (u32 ci = 0; ci < sizeof(checkInsts); ci++) {
                u8 idx = checkInsts[ci];
                if (idx < font->numInstruments && font->instruments[idx]) {
                    Instrument* inst = font->instruments[idx];
                    SoundFontSound* snd = &inst->normalNotesSound;
                    if (snd->sample && snd->sample->sampleAddr) {
                        u8* addr = (u8*)snd->sample->sampleAddr;
                        MMSFX_LOG("[MmSfx] DIAG: inst[%d] sample: size=%u, codec=%d, tuning=%.3f, "
                                  "first8=[%02X %02X %02X %02X %02X %02X %02X %02X]",
                                  idx, snd->sample->size, snd->sample->codec, snd->tuning, addr[0], addr[1], addr[2],
                                  addr[3], addr[4], addr[5], addr[6], addr[7]);
                    } else {
                        MMSFX_LOG("[MmSfx] DIAG: inst[%d] has no sample data", idx);
                    }
                }
            }
            // Check soundEffect[0] and [1] (voice samples)
            for (u32 ei = 0; ei < 3 && ei < font->numSfx; ei++) {
                SoundFontSound* snd = &font->soundEffects[ei];
                if (snd->sample && snd->sample->sampleAddr) {
                    u8* addr = (u8*)snd->sample->sampleAddr;
                    MMSFX_LOG("[MmSfx] DIAG: sfx[%d] sample: size=%u, codec=%d, tuning=%.3f, "
                              "first8=[%02X %02X %02X %02X %02X %02X %02X %02X]",
                              ei, snd->sample->size, snd->sample->codec, snd->tuning, addr[0], addr[1], addr[2],
                              addr[3], addr[4], addr[5], addr[6], addr[7]);
                } else {
                    MMSFX_LOG("[MmSfx] DIAG: sfx[%d] has no sample data", ei);
                }
            }
        }

        // STEP 4: List MM sample bank resources in mm.o2r
        if (sMmArchive) {
            try {
                auto sampleFiles = sMmArchive->ListFiles("audio/samples*");
                if (sampleFiles && sampleFiles->size() > 0) {
                    MMSFX_LOG("[MmSfx] DIAG: Found %zu sample resources in mm.o2r", sampleFiles->size());
                    int shown = 0;
                    for (auto& entry : *sampleFiles) {
                        if (shown < 10) {
                            MMSFX_LOG("[MmSfx] DIAG: MM sample: '%s'", entry.second.c_str());
                        }
                        shown++;
                    }
                    if (shown > 10)
                        MMSFX_LOG("[MmSfx] DIAG: ... and %d more samples", shown - 10);
                }
            } catch (...) {}
        }

        MMSFX_LOG("[MmSfx] DIAG: ===== END DIAGNOSTIC =====");
    }

    // === Route via the MM SFX bank engine (vanilla MM behavior) ===
    // The engine reads the bank tables (importance, sfxParams, randFreq, etc.),
    // applies priority/eviction, then dispatches to MmDirectAudio via the
    // dispatcher bridge once a channel is allocated.
    extern void AudioMmSfx_PlaySfx(u16, Vec3f*, u8, f32*, f32*, s8*);
    extern void AudioMmSfx_Reset(void);
    // Use the static default pos if caller passed NULL — MM's request queue
    // requires a non-NULL Vec3f for the dedup compare (&req->pos->x).
    Vec3f* effectivePos = pos ? pos : &gMmSfxDefaultPos;
    {
        // Serialize the bank-engine state mutation against the audio thread's
        // mixer (which drains AudioMmSfx_ProcessRequests/ProcessActiveSfx). The
        // one-time diagnostics + font load above intentionally run OUTSIDE this
        // lock so we don't hold the audio mutex across ResourceManager I/O.
        MmAudioScopedLock audioLock;
        static s32 sMmSfxEngineInitDone = 0;
        if (!sMmSfxEngineInitDone) {
            AudioMmSfx_Reset();
            sMmSfxEngineInitDone = 1;
        }
        AudioMmSfx_PlaySfx(sfxId, effectivePos, token, freqScale, vol, reverbAdd);
    }
    return 1;
}

void MmSfx_Stop(u16 sfxId) {
    // FIX: Must stop in BOTH the MmDirectAudio playing-sound array AND the
    // AudioMmSfx bank engine. Without the bank-engine stop, the entry stays
    // in PLAYING_REFRESH state and the engine re-triggers playback every
    // audio frame — undoing the StopById fade-out within milliseconds.
    // Symptom: Goron BALL_CHARGE keeps humming after spike activation because
    // the bank engine kept refreshing it even though MmDirectAudio faded it.
    extern void AudioMmSfx_StopById(u32 sfxId);
    // Serialize against the mixer: AudioMmSfx_StopById mutates the bank/request
    // ring + stop-guard that AudioMmSfx_ProcessRequests reads, and
    // MmDirectAudio_StopById mutates sPlayingSounds that MmDirectAudio_MixInto
    // reads — both on the audio thread under this same mutex.
    MmAudioScopedLock audioLock;
    AudioMmSfx_StopById((u32)sfxId);
    MmDirectAudio_StopById(sfxId);
}

// =============================================================================
// MmSfxBridge_* — bridge entrypoints called by mm_audio_sfx_dispatch.cpp.
// Expose the internal MmDirectAudio_Play/Stop functions to the new SFX engine
// without changing their TU-static linkage.
// =============================================================================
s32 MmSfxBridge_Play(u16 mmSfxId, f32 freqScale, Vec3f* pos) {
    return MmDirectAudio_Play(mmSfxId, freqScale, pos);
}

void MmSfxBridge_StopByMmSfxId(u16 mmSfxId) {
    MmDirectAudio_StopById(mmSfxId);
}

// Force-repatch every instrument/drum/sfx sample pointer in `sf` to a
// SoundFontSample loaded directly from mm.o2r. Used by mm_bgm_loader to fix
// stale OOT sample pointers in the global ResourceManager cache after
// re-loading an MM SoundFont. Without this, the audio synth memcpy's from a
// stale OOT sampleAddr and crashes when an MM seq triggers a note.
//
// `path` must be the o2r-relative path (e.g. "audio/fonts/Soundfont_6") —
// same format MmAssets_LoadFromMmArchive expects.
void MmSfxBridge_PatchFontSamples(SoundFont* sf, const char* path) {
    if (sf == nullptr || path == nullptr) {
        return;
    }
    MmSfx_PatchFontSamplesFromMmArchive(sf, path);
}

// Returns 1 if any MmDirectAudio slot is currently playing the given mmSfxId
// (active AND not in late release fade). Used by the MM SFX bank engine to
// detect when a sample has finished playing so it can clean up the bank entry
// — mirrors MM's "channel->seqScriptIO[1] == SEQ_IO_VAL_NONE" check.
s32 MmSfxBridge_IsActive(u16 mmSfxId) {
    for (s32 i = 0; i < MM_DIRECT_MAX_SOUNDS; i++) {
        MmPlayingSound* snd = &sPlayingSounds[i];
        if (snd->active && snd->mmSfxId == mmSfxId) {
            // Slot is alive. Even RELEASE-phase slots count as alive — they
            // still emit audio for a few ms while the envelope decays. Only
            // after the slot is fully released does .active flip to 0.
            return 1;
        }
    }
    return 0;
}

// Update pos/vol/freq on an existing MmDirectAudio slot WITHOUT re-triggering
// the sample. Mirrors MM's AudioSfx_SetProperties — for continuing sustained
// notes whose source position may have moved.
void MmSfxBridge_RefreshProperties(u16 mmSfxId, Vec3f* pos, f32 freqScale) {
    f32 vol, pan;
    MmDirectAudio_ComputeSpatial(pos, &vol, &pan);
    for (s32 i = 0; i < MM_DIRECT_MAX_SOUNDS; i++) {
        MmPlayingSound* snd = &sPlayingSounds[i];
        if (snd->active && snd->mmSfxId == mmSfxId) {
            snd->volume = vol;
            snd->pan = pan;
            snd->lastRefreshFrame = sMmAudioFrame;
        }
    }
}

// MM's Audio_PlaySfx_AtPosWithSyncedFreqAndVolume mapping
// (code_8019AF00.c:4225-4234). Given a freq/vol param:
//   param ≥ 6.0 → freq=1.1, vol=1.0 (full)
//   per −1.0 step below 6: freq −= 0.0333, vol −= 0.0375
// Used by Goron rolling SFX so the cadence/pitch matches MM exactly.
static void MmSfx_ComputeSyncedFreqVol(f32 param, f32* outFreq, f32* outVol) {
    f32 t = (param >= 6.0f) ? 0.0f : (6.0f - param);
    *outFreq = 1.1f - t * 0.0333f;
    *outVol  = 1.0f - t * 0.0375f;
    if (*outFreq < 0.5f) *outFreq = 0.5f;
    if (*outVol  < 0.1f) *outVol  = 0.1f;
}

// Apply MM's `Player_GetFloorSfx` offset: ice floor adds 0xF to the base ID,
// swapping ROLL→ROLL_ICE / CHG_ROLL→CHG_ROLL_ICE. Floor type is detected via
// the caller-supplied floorSfxOffset (matches NA_SE_PL_WALK_* offsets;
// 0xF == NA_SE_PL_WALK_ICE - NA_SE_PL_WALK_GROUND).
static u16 MmSfx_ApplyFloorOffset(u16 baseId, u16 floorSfxOffset) {
    // Only ice swap is meaningful for Goron rolling SFX — other floor offsets
    // don't have corresponding GORON_ROLL_* variants in MM's playerbank.
    if (floorSfxOffset == 0xF) return baseId + 0xF;
    return baseId;
}

void MmSfx_PlayGoronRoll(Vec3f* pos, f32 speed) {
    // MM: Audio_PlaySfx_AtPosWithSyncedFreqAndVolume(pos, GoronRoll[+floorOffset], sp54)
    // where sp54 is the per-frame XZ speed used as freq/vol param.
    f32 freq, vol;
    MmSfx_ComputeSyncedFreqVol(speed, &freq, &vol);
    sTempFreqScale = freq;
    sTempVol = vol;
    MmSfx_PlayEx(MM_NA_SE_PL_GORON_ROLL, pos, 4, &sTempFreqScale, &sTempVol, nullptr);
}

void MmSfx_PlayGoronChgRoll(Vec3f* pos, f32 speed) {
    f32 freq, vol;
    MmSfx_ComputeSyncedFreqVol(speed, &freq, &vol);
    sTempFreqScale = freq;
    sTempVol = vol;
    MmSfx_PlayEx(MM_NA_SE_PL_GORON_CHG_ROLL, pos, 4, &sTempFreqScale, &sTempVol, nullptr);
}

// Variant playback honoring the floor SFX offset (ice→ICE variant).
void MmSfx_PlayGoronRollWithFloor(Vec3f* pos, f32 speed, u16 floorSfxOffset) {
    f32 freq, vol;
    MmSfx_ComputeSyncedFreqVol(speed, &freq, &vol);
    sTempFreqScale = freq;
    sTempVol = vol;
    u16 id = MmSfx_ApplyFloorOffset(MM_NA_SE_PL_GORON_ROLL, floorSfxOffset);
    MmSfx_PlayEx(id, pos, 4, &sTempFreqScale, &sTempVol, nullptr);
}

void MmSfx_PlayGoronChgRollWithFloor(Vec3f* pos, f32 speed, u16 floorSfxOffset) {
    f32 freq, vol;
    MmSfx_ComputeSyncedFreqVol(speed, &freq, &vol);
    sTempFreqScale = freq;
    sTempVol = vol;
    u16 id = MmSfx_ApplyFloorOffset(MM_NA_SE_PL_GORON_CHG_ROLL, floorSfxOffset);
    MmSfx_PlayEx(id, pos, 4, &sTempFreqScale, &sTempVol, nullptr);
}

void MmSfx_PlayGoronCharge(Vec3f* pos, f32 chargeLevel) {
    sTempFreqScale = 0.7f + chargeLevel * 0.6f;
    MmSfx_PlayEx(MM_NA_SE_PL_GORON_BALL_CHARGE, pos, 4, &sTempFreqScale, nullptr, nullptr);
}

void MmSfx_PlayTransformFlash(void) {
    MmSfx_PlayAtPos(MM_NA_SE_SY_TRANSFORM_MASK_FLASH, nullptr);
}

void MmSfx_GetCacheStats(s32* outLoadedFonts, s32* outTotalBytes) {
    if (outLoadedFonts)
        *outLoadedFonts = sSfxCacheCount;
    if (outTotalBytes) {
        size_t total = 0;
        for (s32 i = 0; i < sSfxCacheCount; i++)
            total += sSfxCache[i].sizeBytes;
        *outTotalBytes = (s32)total;
    }
}

void MmSfx_FlushCache(void) {
    for (s32 i = 0; i < MM_SFX_MAX_FONTS; i++) {
        sSfxCache[i].fontId = -1;
        sSfxCache[i].font = nullptr;
        sSfxCache[i].sizeBytes = 0;
    }
    sSfxCacheCount = 0;
}

